  "main.rs": "/// Splits a shell command string into tokens, handling single quotes as bash does.
/// Idiomatic Rust often prefers a simple state machine over complex iterator chains 
/// for parsing algorithms like this, to avoid unnecessary allocations and closures.
fn tokenize(s: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_quotes = false;
    let mut in_token = false;

    for c in s.chars() {
        match c {
            '\'' => {
                // Toggle the quote state.
                in_quotes = !in_quotes;
                // A quote marks the start or continuation of a token (e.g., `''` is an empty token).
                in_token = true;
            }
            ' ' if !in_quotes => {
                // Only split on spaces if we are NOT inside single quotes.
                if in_token {
                    // Use `std::mem::take` to extract the composed token string
                    // and leave an empty string in its place to be reused.
                    tokens.push(std::mem::take(&mut current_token));
                    in_token = false;
                }
            }
            _ => {
                // Any other character is pushed into the current token.
                current_token.push(c);
                in_token = true;
            }
        }
    }

    // If the string cleanly ended while we were still building a token, push it.
    if in_token {
        tokens.push(current_token);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);

    println!("{} args:", tokens.len());
    for token in tokens {
        println!("<{}>", token);
    }
}
"
}

