        let nelems = self.get_nelems();

        // 1. Calculate the pairs in parallel using rayon.
        // We only process `j > i` to avoid redundant calculations and data races.
        // We borrow `self.elems` immutably for the parallel iteration.
        let mut upper_triangle_nbs: Vec<Vec<usize>> = self.elems
            .par_iter()
            .enumerate()
            .map(|(i, elem_i)| {
                let mut nbs = Vec::new();
                // Skip to only compute the remaining unvisited half of the pairs
