/// A recursive function to traverse the `serde_json::Value` tree and resolve `$ref` pointers.
fn resolve_refs(value: &mut Value, base_dir: &Path) {
    let mut resolved_val = None;

    if let Value::Object(map) = value {
        if let Some(ref_str) = map.get("$ref").and_then(Value::as_str) {
            // Split the `$ref` string by '#' into the file path and the JSON pointer.
            let parts: Vec<&str> = ref_str.splitn(2, '#').collect();
            let file_part = parts[0];
            let pointer_part = if parts.len() > 1 { parts[1] } else { "" };

            if !file_part.is_empty() {
                let file_path = base_dir.join(file_part);
                let content = fs::read_to_string(&file_path)
                    .unwrap_or_else(|_| panic!("failed to read ref file: {}", file_path.display()));
                let mut ref_json: Value = serde_json::from_str(&content)
                    .expect("failed to parse ref file");

                if !pointer_part.is_empty() {
                    // Navigate to the target JSON pointer inside the file 
                    let ptr = ref_json.pointer_mut(pointer_part)
                        .unwrap_or_else(|| panic!("pointer '{}' not found in {}", pointer_part, file_path.display()));

                    // Use `std::mem::take` which safely moves out the value, leaving `Value::Null` in its place.
                    resolved_val = Some(std::mem::take(ptr));
                } else {
                    resolved_val = Some(ref_json);
                }
            }
        }
    }

    if let Some(mut new_value) = resolved_val {
        // Recursively resolve references in the newly substituted value as well
        resolve_refs(&mut new_value, base_dir);
        *value = new_value;
    } else {
        // Step into nested structured objects or arrays to resolve deep references
        match value {
            Value::Object(map) => {
                for v in map.values_mut() {
                    resolve_refs(v, base_dir);
                }
            }
            Value::Array(arr) => {
                for v in arr.iter_mut() {
                    resolve_refs(v, base_dir);
                }
            }
            _ => {}
        }
    }
}

