into multiple struct fields using only `#[derive(Deserialize)]` attributes. Serde 
consumes each JSON key exactly once, mapping it to a single target enum/field. 

However, you do NOT need a complex manual `Visitor` implementation, nor do you 
need a helper struct polluting your file scope! 

The cleanest, most idiomatic trick is to manually implement `Deserialize`, but 
enclose an inline Helper struct completely INSIDE the implementation block. 
This offloads all the complicated parsing logic entirely back to Serde, but keeps 
your overall program namespace completely free of extra structs.
*/

use serde::{Deserialize, Deserializer};

#[derive(Debug)]
pub struct Character {
    pub name: String,
    pub ac: u8,
    pub current: u16,
    pub max: u16,
    pub temp: u16,
}

impl<'de> Deserialize<'de> for Character {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        // By defining the helper struct *inside* the custom Deserialize implementation,
        // we avoid the messy "extra struct" lying around in your module. It exists
        // only for this fraction of a second during deserialization!
        #[derive(Deserialize)]
        struct CharacterHelper {
            name: String,
            ac: u8,
            hp: u16,
        }

        // Let Serde do the heavy lifting of parsing the JSON into the helper...
        let helper = CharacterHelper::deserialize(deserializer)?;

        // ...then simply map the fields exactly how you structured your requirements.
        Ok(Character {
            name: helper.name,
            ac: helper.ac,
            current: helper.hp, // mapped from 'hp'
            max: helper.hp,     // mapped from 'hp'
            temp: 0,            // initialized to 0, skipping the need to deserialize
        })
    }
}

fn main() {
