/// Flips a single line of pixels horizontally.
/// 
/// Rather than looping byte by byte or using manual pointer swaps, we safely
/// interpret the flat byte slice as a slice of 4-byte arrays (`[u8; 4]`). 
/// Doing so allows us to use Rust's highly-optimized standard library `reverse()` 
/// function, which LLVM regularly auto-vectorizes into rapid SIMD shuffles or 
/// optimized registry flips under the hood.
#[inline]
pub fn flip_line(line_bytes: &mut [u8]) {
    let pixels = line_bytes.len() / BYTES_PER_PIXEL;

    // SAFETY: 
    // `[u8; BYTES_PER_PIXEL]` strictly possesses an alignment of 1 
    // (which is exactly the same alignment as standard `u8`). 
    // Because both bounds and lengths align perfectly and there are no CPU 
    // Unaligned Memory Access issues, casting the pointer this way is 100% sound. 
