/// A common reason Custom DogStatsD metrics are dropped over Unix Sockets
/// in high-throughput applications is that the default queue limits bound by
/// `QueuingMetricSink::from` and OS-level buffer bounds (`SO_SNDBUF`) fill up
/// faster than the network/agent can consume them. 
///
/// In this setup, we allocate a higher capacity to `QueuingMetricSink` to absorb
/// unexpected bursts of metrics typical of a high throughput Rust server.
pub fn create_statsd_client() -> Arc<StatsdClient> {
    // Drop metrics gracefully if we aren't running in a production environment
    // (e.g. running via `cargo run` without features)
    if cfg!(not(feature = "production")) {
        return Arc::new(StatsdClient::from_sink(METRIC_PREFIX, NopMetricSink));
    }

    let mut retries: usize = 0;
    let unix_sink = loop {
        let sock = UnixDatagram::unbound().expect("failed to create unix datagram");

        // Optionally increase the socket's send buffer via `nix` or `socket2` crates 
        // if internal queues are still overflowing to the Datadog Agent.
        // let _ = sock.set_nonblocking(true);

        match sock.connect(SOCKET_PATH) {
            Ok(_) => {
