                break BufferedUnixMetricSink::from(SOCKET_PATH, sock);
            }
            Err(e) => {
                eprintln!("datadog socket not ready: {e}, retrying...");
                std::thread::sleep(Duration::from_secs(2));
                retries += 1;
            }
        }

        if retries >= MAX_RETRIES {
            panic!("failed to connect to dogstatd socket");
        }
    };

    // By explicitly using `with_capacity`, we override the default bound queue sizes which
    // silently drop thousands of metrics when the internal consumer threshold limits are reached.
    let queuing_sink = QueuingMetricSink::with_capacity(unix_sink, 1024 * 512);

    Arc::new(
        StatsdClient::builder(METRIC_PREFIX, queuing_sink)
            .with_error_handler(|e| eprintln!("[STATSD_ERR]: {e:?}"))
            .build(),
