// We store a global reference to the dragged element's state so we can mutate it 
// from the parent mouse tracker without re-rendering the parent.
#[derive(Clone, Copy)]
pub struct DragContext {
    pub active_drag: Signal<Option<DragState>>,
}

#[derive(Clone, Copy)]
pub struct DragState {
    // A handle to the child's core state
    pub target_signal: Signal<(f64, f64)>,
    // The initial mouse position when dragging started
    pub initial_mouse: (f64, f64),
    // The initial position of the dragged element
    pub initial_target_pos: (f64, f64),
}

