pub fn App() -> Element {
    // Provide our global context for drag interactions
    let mut drag_ctx = use_context_provider(|| DragContext {
        active_drag: Signal::new(None),
    });

    rsx! {
        div {
            // Track mouse events globally so dragging doesn't break when mouse leaves the element wrapper
            onmousemove: move |e| {
                // If we are currently drag tracking an item...
                if let Some(state) = *drag_ctx.active_drag.read() {
                    let client = e.client_coordinates();
                    let current_mouse = (client.x as f64, client.y as f64);

                    let dx = current_mouse.0 - state.initial_mouse.0;
                    let dy = current_mouse.1 - state.initial_mouse.1;

                    // Mutate the child's signal directly. 
                    // This causes ONLY the specific child to re-render!
                    let mut target = state.target_signal;
                    target.set((
                        state.initial_target_pos.0 + dx, 
                        state.initial_target_pos.1 + dy
                    ));
                }
            },
            onmouseup: move |_| {
                // Stop dragging when mouse goes up anywhere
                drag_ctx.active_drag.set(None);
            },
