// 2. We use a Marker trait pattern to allow multiple implementations
// without tripping Rust's overlapping implementation rules.
pub trait IntoHandler<Marker> {
    fn into_handler(self) -> Handler;
}

pub struct SyncMarker;
pub struct AsyncMarker;

