use base64::prelude::*;
use termion::terminal_size_pixels;
use std::ffi::CString;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;

// We use 3 buffers (triple buffering) to guarantee Kitty finishes reading a buffer
// before we overwrite it for the next frames.
const NUM_BUFFERS: usize = 3;

struct ShmBuffer {
    name: CString,
    pub b64_name: String,
    ptr: *mut u8,
    size: usize,
}

impl ShmBuffer {
    fn new(name: &str, size: usize) -> Self {
        // Kitty requires POSIX shm files to start with a slash and have no other slashes.
        let name_with_slash = format!("/{}", name);
        let c_name = CString::new(name_with_slash.clone()).unwrap();

        // The payload for Kitty is the base64 encoded string of the shm file name.
        let b64_name = BASE64_STANDARD.encode(name_with_slash.as_bytes());

        unsafe {
            // Try unlinking it first in case a previous run crashed and leaked it
            libc::shm_unlink(c_name.as_ptr());

            let fd = libc::shm_open(
                c_name.as_ptr(),
                libc::O_CREAT | libc::O_RDWR | libc::O_EXCL,
                0o600,
            );
            if fd < 0 {
                panic!("shm_open failed for {}", name_with_slash);
            }
            if libc::ftruncate(fd, size as libc::off_t) < 0 {
                panic!("ftruncate failed");
            }
            let ptr = libc::mmap(
                std::ptr::null_mut(),
                size,
                libc::PROT_READ | libc::PROT_WRITE,
                libc::MAP_SHARED,
                fd,
                0,
            );
            if ptr == libc::MAP_FAILED {
                panic!("mmap failed");
            }

            // We can safely close the file descriptor now that it's mapped
            libc::close(fd);

            ShmBuffer {
                name: c_name,
                b64_name,
                ptr: ptr as *mut u8,
                size,
            }
        }
    }

    #[inline]
    fn as_mut_slice(&mut self) -> &mut [u8] {
        unsafe { std::slice::from_raw_parts_mut(self.ptr, self.size) }
    }
}

impl Drop for ShmBuffer {
    fn drop(&mut self) {
        // Clean up the memory mapping and delete the file from `/dev/shm`
        unsafe {
            libc::munmap(self.ptr as *mut libc::c_void, self.size);
            libc::shm_unlink(self.name.as_ptr());
        }
    }
}

fn main() {
    let (mut width, mut height) = terminal_size_pixels().unwrap_or((640, 480));
    if width == 0 || height == 0 {
        width = 640;
        height = 480;
    }
    let (width, height) = (width as usize, height as usize);

    // Create shared memory buffers uniquely keyed to this process ID
    let pid = std::process::id();
    let mut buffers = Vec::new();
    for i in 0..NUM_BUFFERS {
        let name = format!("kitty_anim_{}_{}", pid, i);
        buffers.push(ShmBuffer::new(&name, width * height * 3));
    }

    // Catch Ctrl-C securely to ensure shared memory objects run their Drop execution correctly
    let running = Arc::new(AtomicBool::new(true));
    let r = running.clone();
    ctrlc::set_handler(move || {
        r.store(false, Ordering::SeqCst);
    }).expect("Error setting Ctrl-C handler");

    let stdout = io::stdout();
    let mut handle = stdout.lock();

    // Clear screen entirely and hide terminal cursor to establish clean drawing region
    write!(handle, "\x1b[2J\x1b[?25l").unwrap();
    handle.flush().unwrap();

    let mut buf_idx = 0;
    let start_time = std::time::Instant::now();
    let frame_duration = std::time::Duration::from_secs_f64(1.0 / 60.0);
    let mut next_frame_time = std::time::Instant::now() + frame_duration;

    let pi = std::f32::consts::PI;

    while running.load(Ordering::Relaxed) {
        let time = start_time.elapsed().as_secs_f32() * 2.0;
        let frame = buffers[buf_idx].as_mut_slice();

        let mut i = 0;
        let r_time = time;
        let g_time = time * 1.3;
        let b_time = time * 0.7;

        // Write image pixels directly to shared memory using array allocation pointer slices.
        // Mathematical calculations can be slightly optimized by precomputing `y` constants out the inner loop.
        for y in 0..height {
            let fy = y as f32 / height as f32;
            let fy_pi = fy * pi;

            let g = ((fy_pi + g_time).sin() * 0.5 + 0.5) * 255.0;
            let g_u8 = g as u8;

            for x in 0..width {
                let fx = x as f32 / width as f32;
                let fx_pi = fx * pi;

                let r = ((fx_pi + r_time).sin() * 0.5 + 0.5) * 255.0;
                let b = ((fx_pi + fy_pi + b_time).sin() * 0.5 + 0.5) * 255.0;

                frame[i] = r as u8;
                frame[i + 1] = g_u8;
                frame[i + 2] = b as u8;
                i += 3;
            }
        }

        // Instead of chunking Base64 string blobs, directly point Kitty to the shared memory string reference name
        // i=1 replaces the existing image at ID 1, guaranteeing the memory footprint doesn't increase.
        write!(handle, "\x1b[H").unwrap();
        write!(
            handle,
            "\x1b_Ga=T,f=24,s={},v={},t=s,i=1;{}\x1b\\",
            width, height, buffers[buf_idx].b64_name
        ).unwrap();
        handle.flush().unwrap();

        buf_idx = (buf_idx + 1) % NUM_BUFFERS;

        let now = std::time::Instant::now();
        if now < next_frame_time {
            std::thread::sleep(next_frame_time - now);
        }
        next_frame_time = std::time::Instant::now().max(next_frame_time + frame_duration);
    }

    // Remove the Kitty image ID (`a=d`), clear screen contents, bring back the cursor.
    write!(handle, "\x1b_Ga=d,d=A\x1b\\\x1b[2J\x1b[H\x1b[?25h").unwrap();
    handle.flush().unwrap();
}
"
