  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};
use std::time::Duration;

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Creates a custom waker that does nothing.
/// Note: On Rust 1.85+, you can simply use `Waker::noop()` instead.
fn dummy_waker() -> Waker {
    const VTABLE: RawWakerVTable = RawWakerVTable::new(
        |_| RawWaker::new(std::ptr::null(), &VTABLE),
        |_| {}, // wake
        |_| {}, // wake_by_ref
        |_| {}, // drop
    );
    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

/// Synchronously attempts to poll a future.
/// We require `Pin<&mut F>` as a parameter to safely accommodate arbitrary futures.
fn try_poll<X>(mut future: Pin<&mut impl Future<Output = X>>) -> TryPollResult<X> {
    let waker = dummy_waker();
    let mut cx = Context::from_waker(&waker);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(x) => TryPollResult::Ready(x),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// A non-async function executing inside an async context.
/// (It can safely interact with Tokio resources because the thread-local context exists).
fn process_sync_in_async_context() {
    // 1. Example of a future that is ready immediately.
    // Using `Box::pin` gives us a `'static` future that is pinned,
    // allowing us to poll it (by re-borrowing) and later spawn it if needed.
    let mut ready_fut = Box::pin(async {
        42
    });

    match try_poll(ready_fut.as_mut()) {
        TryPollResult::Ready(value) => {
            println!("Future 1 was immediately Ready with: {}", value);
        }
        TryPollResult::Pending => {
            // In this case it won't hit, but if it did, we move the Box to the task
            tokio::spawn(async move { ready_fut.await; });
        }
    }

    // 2. Example of a future that yields and is pending.
    let mut pending_fut = Box::pin(async {
        // Relies on Tokio's async context. Will succeed because `process_sync_in_async_context`
        // is executed on a Tokio thread, even though the function itself is sync.
        tokio::time::sleep(Duration::from_millis(100)).await;
        100
    });

    match try_poll(pending_fut.as_mut()) {
        TryPollResult::Ready(value) => {
            println!("Future 2 was immediately Ready with: {}", value);
        }
        TryPollResult::Pending => {
            println!("Future 2 returned Pending! Spawning tokio task to finish it.");

            // Since `pending_fut` is a Boxed future, it is an owned, 'static value.
            // We can transfer ownership to a newly spawned async task. Tokio's reactor
            // will re-poll it with a *real* Waker, replacing the dummy waker.
            tokio::spawn(async move {
                let final_value = pending_fut.await;
                println!("Future 2 completed inside spawned task with: {}", final_value);
            });
        }
    }
}

#[tokio::main]
async fn main() {
    println!("--- Starting application...");

    // Call the synchronous processing function.
    process_sync_in_async_context();

    // Wait enough time to ensure the second spawned task resolves before main finishes.
    tokio::time::sleep(Duration::from_millis(150)).await;
    println!("--- Application done.");
}
"
