#[derive(Default)]
pub struct WadEntryLoader;

impl AssetLoader for WadEntryLoader {
    type Asset = WadEntry;
    type Settings = ();
    type Error = std::io::Error;

    async fn load<'a>(
        &'a self,
        reader: &'a mut Reader<'_>,
        _settings: &'a Self::Settings,
        _load_context: &'a mut LoadContext<'_>,
    ) -> Result<Self::Asset, Self::Error> {
