    }

    fn extensions(&self) -> &[&str] {
        &["wadt"] // e.g. "wad text" format extension
    }
}

/// The Custom AssetReader. 
/// This captures paths like `wad://archive.wad/asset.wadt` and lazily extracts just the bytes needed.
pub struct WadReader {
    base_path: PathBuf,
