// Note: This implements a custom reader synchronously for the sake of an easy, contained example.
// In production with massive WADs, you should consider utilizing `async_fs::File` so it
// doesn't block the Bevy executor's async worker threads during an I/O read.
impl AssetReader for WadReader {
    async fn read<'a>(&'a self, path: &'a Path) -> Result<Box<Reader<'a>>, AssetReaderError> {
        // E.g., "my_archive.wad/test1.wadt" splits into archive file + specific asset entry
        let path_str = path.to_str().ok_or_else(|| AssetReaderError::NotFound(path.to_path_buf()))?.replace('\\', "/");
        let mut parts = path_str.splitn(2, '/');
        let archive_name = parts.next().unwrap();
        let entry_name = parts.next().ok_or_else(|| AssetReaderError::NotFound(path.to_path_buf()))?;

        // The `assets/` directory (where we placed the archive file)
        let physical_path = self.base_path.join(archive_name);
        let mut file = File::open(&physical_path).map_err(|_| AssetReaderError::NotFound(path.to_path_buf()))?;

        // --- FAKE WAD PARSING LOGIC ---
        // In a real loader, you might cache the header offsets inside a Resource or lazy dictionary
        // so you don't rescan the entire header for every loaded texture.
        let mut magic = [0u8; 4];
        file.read_exact(&mut magic).map_err(|_| AssetReaderError::NotFound(path.to_path_buf()))?;
        if &magic != b"WAD!" {
            return Err(AssetReaderError::NotFound(path.to_path_buf()));
        }

        let mut num_entries_bytes = [0u8; 4];
        file.read_exact(&mut num_entries_bytes).unwrap();
        let num_entries = u32::from_le_bytes(num_entries_bytes);

        let mut found_offset = None;
        let mut found_length = None;

        for _ in 0..num_entries {
            let mut name_len_b = [0u8; 4];
            file.read_exact(&mut name_len_b).unwrap();

            let mut name_b = vec![0u8; u32::from_le_bytes(name_len_b) as usize];
            file.read_exact(&mut name_b).unwrap();

            let mut offset_b = [0u8; 4];
            file.read_exact(&mut offset_b).unwrap();
            let offset = u32::from_le_bytes(offset_b);

