        let task = EVENT_LOOP.with(|q| {
            let mut queue = q.borrow_mut();
            if queue.is_empty() {
                None
            } else {
                Some(queue.remove(0))
            }
        });
        match task {
            Some(t) => t(),
            None => break,
        }
    }
