async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    if socket.send(Message::Text(format!("Hello {}", session_id))).await.is_ok() {
        while let Some(msg) = socket.recv().await {
            if let Ok(msg) = msg {
                let _ = socket.send(msg).await;
            } else {
                break; // client disconnected
            }
        }
    }
}

// Middleware to check WebSocket origins globally or per-router limit.
async fn check_ws_origin(req: Request, next: Next) -> Response {
    if let Some(upgrade) = req.headers().get(header::UPGRADE) {
        if upgrade.as_bytes().eq_ignore_ascii_case(b"websocket") {
            let origin = req.headers().get(header::ORIGIN);
            let allowed_origin = HeaderValue::from_static("https://www.example.com");

            if origin != Some(&allowed_origin) {
                return (StatusCode::FORBIDDEN, "Forbidden").into_response();
            }
        }
    }

    // Proceed to next layer / handler if it doesn't violate origin policy.
    next.run(req).await
}

#[tokio::main]
async fn main() {
    let app = Router::new()
        .route("/client/:session_id", get(client_handler))
        // We add our middleware layer here. It can be applied closely to specific routes
        // or globally depending on where `layer` is chained.
        .layer(middleware::from_fn(check_ws_origin))
        .layer(
            CorsLayer::new()
                .allow_origin("https://www.example.com".parse::<HeaderValue>().unwrap())
                .allow_methods([Method::GET, Method::POST])
                .allow_headers([header::CONTENT_TYPE]),
        );

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();

    println!("Listening on http://{}", addr);
    axum::serve(listener, app).await.unwrap();
}
