fn main() {
    // 1. Create an n x k matrix (e.g. 4 samples, 3 features)
    // nalgebra is column-major, but from_row_slice makes defining it visually clearer
    let matrix = DMatrix::from_row_slice(4, 3, &[
        1.0, 2.0, 3.0,
        4.0, 6.0, 8.0,
        7.0, 10.0, 13.0,
        10.0, 14.0, 18.0
    ]);

    println!("Original matrix (4x3):\n{}", matrix);

    // Compute the mean of each column -> 1 x k row vector
    let mut mean = RowDVector::<f64>::zeros(matrix.ncols());
    for (i, col) in matrix.column_iter().enumerate() {
        mean[i] = col.mean();
    }
    println!("Column means (1x3):\n{}", mean);

    // ==============================================================
    // Method 1: Iterating over rows ("Zero-allocation Broadcasting")
    // ==============================================================
    // Because nalgebra does not natively do implicit broadcasting 
    // for matrix subtraction, you can iterate over the rows and perform
    // subtraction directly. The slice dimensions map cleanly.
    let mut centered_by_row = matrix.clone();
    for mut row in centered_by_row.row_iter_mut() {
        row -= &mean;
    }
    println!("Centered (Iterating Rows):\n{}", centered_by_row);

    // ==============================================================
    // Method 2: Idiomatic column centering (Optimal Cache Performance)
    // ==============================================================
    // Since DMatrix is column-major under the hood, dealing with
    // entire columns efficiently avoids strided memory access.
    // This is the most idiomatic way to compute covariance matrices.
    let mut centered_by_col = matrix.clone();
    for mut col in centered_by_col.column_iter_mut() {
        let col_mean = col.mean();
        // col is a 1D column slice, so we subtract the scalar mean from its elements
        col.iter_mut().for_each(|x| *x -= col_mean);
    }
    println!("Centered (Iterating Columns):\n{}", centered_by_col);

    // ==============================================================
    // Method 3: Explicit Expansion (Memory-heavy exact equivalent)
    // ==============================================================
    // If you explicitly want standard matrix subtraction logic identical 
    // to what math broadcasting does under the hood:
    let broadcasted_mean = DMatrix::from_fn(matrix.nrows(), matrix.ncols(), |_, c| mean[c]);
    let centered_explicit = &matrix - broadcasted_mean;
    println!("Centered (Explicit Broadcast Allocation):\n{}", centered_explicit);

    // Verify all approaches yield the exact same result
    assert_eq!(centered_by_row, centered_by_col);
    assert_eq!(centered_by_row, centered_explicit);
}
