/// This function hosts the main rustyline REPL and orchestrates the child process.
fn host_main() -> rustyline::Result<()> {
    // Spawn the same Rust executable but with a "child" argument 
    // to route it to `child_main()`
    let exe = env::current_exe().unwrap();
    let mut child = Command::new(exe)
        .arg("child")
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .spawn()
        .expect("Failed to spawn child process");

    let mut rl = DefaultEditor::new()?;

    // Create an ExternalPrinter to print messages asynchronously.
    // This correctly displays lines above the current interactive prompt 
    // without interrupting what the user is currently typing.
    let mut printer = rl.create_external_printer()?;

    let child_stdout = child.stdout.take().unwrap();
    let mut child_stdin = child.stdin.take().unwrap();

    // Spawn a background thread that continually reads from the child process's stdout
    // and prints it using the ExternalPrinter.
    thread::spawn(move || {
        let reader = io::BufReader::new(child_stdout);
        for line in reader.lines() {
            if let Ok(line) = line {
                // Use printer to safely print asynchronously during a blocking readline() call.
                // Note: Ensure we add a newline `\n` at the end.
                let _ = printer.print(format!("{}\n", line));
            }
        }
    });

    loop {
        // readline blocks until the user presses enter
        let readline = rl.readline("> ");
        match readline {
            Ok(line) => {
                // Add to history
                let _ = rl.add_history_entry(line.as_str());

                // Send the command down to the child process
                if writeln!(child_stdin, "{}", line).is_err() {
                    println!("Child process exited unexpectedly.");
                    break;
                }
            },
            Err(ReadlineError::Interrupted) | Err(ReadlineError::Eof) => {
                println!("Exiting REPL...");
                break;
            },
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }

    // Gracefully clean up the child process upon exit
    let _ = child.kill();
    Ok(())
}

fn main() -> rustyline::Result<()> {
    // Cheap trick to multiplex host and child within the same executable
    if env::args().nth(1).as_deref() == Some("child") {
        child_main();
        Ok(())
    } else {
        host_main()
    }
