pub fn list_property<T>(ui: &mut Ui, title: &str, value_mut: &mut Vec<T>, interactable: bool)
where
    T: Default + 'static,
{
    let header_name = if title.is_empty() { "List Elements" } else { title };
    egui::CollapsingHeader::new(header_name)
        .default_open(true)
        .enabled(interactable)
        .show(ui, |ui| {
            ui.horizontal_top(|ui| {
                if ui.button("➕ Add").clicked() {
                    value_mut.push(T::default());
                }
            });

            let mut i = 0;
            while i < value_mut.len() {
                ui.horizontal(|ui| {
                    // Auto-coercing `&mut T` to `&mut dyn Any` naturally here!
                    downcast_property(ui, "", &mut value_mut[i], interactable);
                    if ui.button("❌").on_hover_text("Remove").clicked() {
                        value_mut.remove(i);
                    } else {
                        i += 1;
                    }
                });
            }
        });
}

pub fn option_property<T>(ui: &mut Ui, title: &str, value_mut: &mut Option<T>, interactable: bool)
where
    T: Default + 'static,
{
    let mut is_option_none = value_mut.is_none();

    ui.horizontal(|ui| {
        if !title.is_empty() {
            ui.label(title);
            ui.add_space(PROPERTY_LABEL_PADDING);
        }
        bool_property(ui, "None", &mut is_option_none, interactable);
        ui.add_space(2.0);
        if is_option_none {
            *value_mut = None;
        } else {
            if let Some(inner) = value_mut.as_mut() {
                // Auto-coercing `&mut T` to `&mut dyn Any` naturally here!
                downcast_property(ui, "", inner, interactable);
            } else {
                *value_mut = Some(T::default());
            }
        }
    });
}

