use std::pin::Pin;

pub struct Context(pub i32); // example

pub enum InnerAsyncEvent {
    DoWithContext {
        // Note: we swap `Fn` for `FnOnce` here. 
        // Events are usually consumed once, and using `FnOnce` permits callers to 
        // take ownership of captures (e.g., using `move` or moving an `Arc` into the future).
        block: Box<
            dyn for<'a> FnOnce(
