// Utility Helper Trait
// ------------------------------------------------------------------
// In stable Rust, to cleanly encode "closure returning a Future that is Send 
// and bound to the argument's lifetime", the accepted practice is using a helper trait.
// This allows the compiler's HRTB (Higher-Rank Trait Bounds) inference to correctly map
// normal closures returning async blocks to generic types.

pub trait AsyncHelper<'a> {
    type Fut: Future<Output = ()> + Send + 'a;
    fn call_once(self, ctx: &'a mut Context) -> Self::Fut;
}

impl<'a, F, Fut> AsyncHelper<'a> for F
where
    F: FnOnce(&'a mut Context) -> Fut,
    Fut: Future<Output = ()> + Send + 'a,
{
    type Fut = Fut;
    fn call_once(self, ctx: &'a mut Context) -> Self::Fut {
        // Execute the closure to produce the future
        self(ctx) 
    }
}

// ------------------------------------------------------------------
// The Helper Function you requested
// ------------------------------------------------------------------
// We depend on the `for<'a> AsyncHelper<'a>` bound to enforce thread-safety correctly,
// while completely hiding the `Box::new` + `Box::pin` boilerplate from the user.

pub async fn with_context_async<F>(
    work_sender: &tokio::sync::mpsc::Sender<InnerAsyncEvent>,
    block: F,
) -> Result<(), tokio::sync::mpsc::error::SendError<InnerAsyncEvent>>
where
    F: for<'a> AsyncHelper<'a> + Send + 'static,
{
    let event = InnerAsyncEvent::DoWithContext {
        block: Box::new(move |ctx| Box::pin(block.call_once(ctx))),
    };

    // Send it to the worker loop
    work_sender.send(event).await
}

// ------------------------------------------------------------------
// Test Run
// ------------------------------------------------------------------
#[tokio::main]
async fn main() {
    let (tx, mut rx) = tokio::sync::mpsc::channel(10);

    // Calling the utility is now incredibly clean without internal pinning at the call site:
    // We use a regular closure producing an async move block!
    // (For users on Rust 1.85+, true `async |ctx: &mut Context| {}` standard closures also work perfectly here)
    with_context_async(&tx, |ctx: &mut Context| async move {
        ctx.0 += 1;
    })
    .await
    .unwrap();

    let handle = tokio::spawn(async move {
        let mut ctx = Context(0);

        // The worker thread receives the event and consumes it
        if let Some(event) = rx.recv().await {
            let fut = match event {
                InnerAsyncEvent::DoWithContext { block } => block(&mut ctx),
            };
            fut.await;
        }

        // Validate functionality
        assert_eq!(ctx.0, 1);
        println!("Success! Modified Context successfully across bound threads. Value = {}", ctx.0);
    });

    handle.await.unwrap();
}
"
}
