                //    candidates: `Foo` AND `PleaseProvideAnInherentMethodNamedGo`.
                //    This triggers an immediate compile-time ambiguity error (E0034)
                //    preventing the macro from creating infinite recursion.
                Self::go(self);
            }
        }
