// To answer your underlying question: it is simply impossible to do this using
// only native Serde field attributes (like `rename` or `alias`). Serde parses 
// the input as a stream and consumes each key-value pair from the JSON exactly 
// once. You cannot map one consumed JSON key into two distinct struct fields.
//
// Even though you mentioned disliking helper structs, the most idiomatic and 
// simplest solution in Serde actually utilizes one combined with `#[serde(from)]`.
// This approach removes the need for complex, manual `Deserialize` trait and Visitor
// implementations, while keeping your main `Character` struct perfectly clean and 
// strictly decoupled from the JSON mapping logic.

#[derive(Debug, Deserialize)]
#[serde(from = "CharacterHelper")] // Serde will automatically deserialize `CharacterHelper` first
struct Character {
    name: String,
    ac: u8,
    current: u16,
    max: u16,
    temp: u16,
}

// A lightweight, private helper struct that mirrors the incoming JSON exactly.
// By keeping this private to the module, it won't clutter the rest of your program.
#[derive(Deserialize)]
struct CharacterHelper {
    name: String,
    ac: u8,
    hp: u16,
}

// This single trait implementation bridges them automatically.
impl From<CharacterHelper> for Character {
    fn from(helper: CharacterHelper) -> Self {
        Character {
            name: helper.name,
            ac: helper.ac,
            current: helper.hp,
            max: helper.hp,   // Map from 'hp' to 'max'
            temp: 0,          // Auto-initialize temp HP to 0
        }
    }
}

fn main() {
    let json_data = r#"{
        "name": "Henry",
        "ac": 16,
        "hp": 54
    }"#;

    // You interact directly with `Character`, the helper struct is invisible here!
    let character: Character = serde_json::from_str(json_data).expect("Failed to deserialize");

    println!("{:#?}", character);

    assert_eq!(character.current, 54);
    assert_eq!(character.max, 54);
    assert_eq!(character.temp, 0);
}
"
}
