// blocking file reads uncancelable from other threads. The idiomatic approach is 
// polling with a timeout (using crossterm) combined with an atomic shutdown flag.
fn yield_keys(sender: Sender<Message>, running: Arc<AtomicBool>) -> thread::JoinHandle<()> {
    thread::spawn(move || {
