    // Flag to control the key event polling thread
    let running = Arc::new(AtomicBool::new(true));

    let (sig_thread, sig_handle) = yield_signals(sender.clone());
    let key_thread = yield_keys(sender.clone(), Arc::clone(&running));

    println!("Event loop started. Press \'q\' or \'Ctrl+C\' to quit.\r");

    // Consuming receiver blocks until sender instances are dropped or we explicitly break.
    for msg in receiver {
        match msg {
