/// Represents a fully expanded import path.
#[derive(Debug, Clone, PartialEq, Eq)]
struct FlatImport {
    path: Vec<String>,
    star: bool,
    alias: Option<String>,
}

/// Flattens a use tree into a list of absolute path components and their properties.
fn flatten_use_tree(tree: &ast::UseTree, current_path: Vec<String>, out: &mut Vec<FlatImport>) {
    let mut path = current_path;
    if let Some(p) = tree.path() {
        for segment in p.segments() {
            path.push(segment.to_string().trim().to_string());
        }
    }

    let star = tree.star_token().is_some();
    let alias = tree.rename().and_then(|r| r.name()).map(|n| n.to_string());

    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            flatten_use_tree(&child, path.clone(), out);
        }
    } else {
        out.push(FlatImport { path, star, alias });
    }
}

/// A Trie structure used to intelligently re-compress flat paths back into a nested import block.
#[derive(Default, Debug, Clone)]
struct ImportNode {
    children: BTreeMap<String, ImportNode>,
    is_star: bool,
    is_self: bool,
    alias: Option<String>,
}

impl ImportNode {
    fn insert(&mut self, path: &[&str], is_star: bool, alias: Option<String>) {
        if path.is_empty() {
            if is_star {
                self.is_star = true;
            } else {
                self.is_self = true;
                self.alias = alias;
            }
            return;
        }
        self.children
            .entry(path[0].to_string())
            .or_default()
            .insert(&path[1..], is_star, alias);
    }
}

/// Recursively format the `ImportNode` trie back into a valid Rust import string.
fn format_node(node: &ImportNode) -> Option<String> {
    let mut parts = Vec::new();
    if node.is_star {
        parts.push("*".to_string());
    }
    if node.is_self {
        if let Some(alias) = &node.alias {
            parts.push(format!("self as {}", alias));
        } else if !node.children.is_empty() {
            parts.push("self".to_string());
        }
    }

    for (name, child) in &node.children {
        if let Some(child_str) = format_node(child) {
            // Automatically fold un-nested pure leaf aliases into simple standard paths
            if child_str.starts_with("self as ") 
                && !child_str.contains("::") 
                && !child_str.contains(',')
            {
                let alias = child_str.strip_prefix("self as ").unwrap();
                parts.push(format!("{} as {}", name, alias));
            } else {
                parts.push(format!("{}::{}", name, child_str));
            }
        } else {
            parts.push(name.clone());
        }
    }

    if parts.is_empty() {
        None
    } else if parts.len() == 1 {
        Some(parts[0].clone())
    } else {
        Some(format!("{{{}}}", parts.join(", ")))
    }
}

pub fn rewrite_imports(code: &str) -> String {
    // Parse file into an AST, clone it to obtain a mutable syntax tree for in-place edits.
    let parsed = SourceFile::parse(code, Edition::Edition2021);
    let root = parsed.tree().syntax().clone_for_update();

    // Hunt down all `use` constructs in the code tree.
    for use_item in root.descendants().filter_map(ast::Use::cast) {
        let Some(tree) = use_item.use_tree() else {
            continue;
        };

        // 1. Flatten into an absolute path sequence representation
        let mut imports = Vec::new();
        flatten_use_tree(&tree, Vec::new(), &mut imports);
        let original_imports = imports.clone();

        let mut changed = false;

        // 2. Perform mappings logically decoupled from structural brackets
        for import in &mut imports {
            if import.path.len() >= 2 && import.path[0] == "vexide" && import.path[1] == "devices" {
                import.path.remove(1); // drops "devices"
                changed = true;
            }
        }

        // Skip edits entirely for unrelated nodes; pristine comment preservation
        if !changed || original_imports == imports {
            continue;
        }

        // 3. Compress heavily modified imports back into a Trie grouping
        let mut trie = ImportNode::default();
        for import in imports {
            let path_refs: Vec<&str> = import.path.iter().map(|s| s.as_str()).collect();
            trie.insert(&path_refs, import.star, import.alias);
        }

        // 4. Generate the optimized canonical string form of the import structure
        let formatted = format_node(&trie).unwrap_or_default();
        if formatted.is_empty() {
            ted::remove(use_item.syntax());
            continue;
        }

        // 5. Build an isolated dummy wrapper, parse back out its AST element via `SourceFile`
        let dummy_code = format!("use {};", formatted);
        let dummy_file = SourceFile::parse(&dummy_code, Edition::Edition2021).tree();
        let new_use_item = dummy_file
            .syntax()
            .descendants()
            .find_map(ast::Use::cast)
            .unwrap();

        // 6. Transplant the fresh UseTree exactly in-place over the old one.
        // Mutating the precise node within `clone_for_update` keeps file doc/comments completely untouched.
        let new_tree = new_use_item.use_tree().unwrap();
        ted::replace(tree.syntax(), new_tree.syntax().clone_for_update());
    }

    // Dump our locally modified copy of the source code
    root.to_string()
}
"
