#[tokio::main]
async fn main() {
    let incoming_data = String::from(r#"{"data": "hello", "more_data": "world"}"#);

    // We deserialize the JSON once, creating a struct that intrinsically owns 
    // the String and the borrowed MyData internally.
    // Using TryBuilder guarantees we can idiomatically handle standard Result outputs.
    let payload = DeserializedPayloadTryBuilder {
        payload: incoming_data,
        parsed_builder: |payload: &String| -> Result<MyData<'_>, serde_json::Error> {
            serde_json::from_str(payload)
        },
    }
    .try_build()
    .expect("Valid JSON should parse successfully");

    // We wrap it in an Arc to safely pass references to the self-referencing struct 
    // across multiple tokio tasks without cloning the original string.
    let shared_payload = Arc::new(payload);

    let mut handles = vec![];

