    ray_dir: Vec3,
    aabb_min: Vec3,
    aabb_max: Vec3,
    obb_transform: &Transform,
) -> Option<(f32, Vec3)> {
    let inv_transform = obb_transform.compute_matrix().inverse();
    let local_origin = inv_transform.transform_point3(ray_origin);
    let local_dir = inv_transform.transform_vector3(ray_dir);

    let mut tmin = f32::NEG_INFINITY;
    let mut tmax = f32::INFINITY;
    let mut local_hit_normal = Vec3::ZERO;

    for i in 0..3 {
        if local_dir[i].abs() < 1e-8 {
            if local_origin[i] < aabb_min[i] || local_origin[i] > aabb_max[i] {
                return None;
            }
