            let inv_d = 1.0 / local_dir[i];
            let mut t0 = (aabb_min[i] - local_origin[i]) * inv_d;
            let mut t1 = (aabb_max[i] - local_origin[i]) * inv_d;
            let mut normal0 = Vec3::ZERO; normal0[i] = -1.0;
            let mut normal1 = Vec3::ZERO; normal1[i] = 1.0;

            if t0 > t1 {
