/// A global state for handling drag actions.
/// 
/// By passing the target `Signal` to this context rather than reading it 
/// uniformly across components, only the active signal's component will 
/// rerender when the parent moves the mouse.
#[derive(Clone, Copy)]
pub struct DragState {
    pub active_target: Signal<Option<Signal<(f64, f64)>>>,
    pub offset: Signal<(f64, f64)>,
}

impl DragState {
    pub fn new() -> Self {
        Self {
            active_target: Signal::new(None),
            offset: Signal::new((0.0, 0.0)),
        }
    }

    pub fn start_drag(&self, target: Signal<(f64, f64)>, mouse_pos: (f64, f64)) {
        let current_pos = *target.read();
        self.offset.set((
            mouse_pos.0 - current_pos.0,
            mouse_pos.1 - current_pos.1,
        ));
        self.active_target.set(Some(target));
    }

    pub fn stop_drag(&self) {
        self.active_target.set(None);
    }

    pub fn handle_mouse_move(&self, mouse_pos: (f64, f64)) {
        if let Some(mut target) = *self.active_target.read() {
            let offset = *self.offset.read();
            target.set((
                mouse_pos.0 - offset.0,
                mouse_pos.1 - offset.1,
            ));
        }
    }
}

#[component]
pub fn DragProvider(children: Element) -> Element {
    let drag_state = use_context_provider(|| DragState::new());

    rsx! {
        div {
            id: "drag_provider",
            // Make sure the provider wraps the whole interactive context natively
            style: "width: 100vw; height: 100vh; position: relative;",
            onmousemove: move |me| {
                // Send coordinate updates directly to the targeted signal only
                let coords = me.element_coordinates();
                drag_state.handle_mouse_move((coords.x, coords.y));
            },
            // Terminate dragging if the mouse unclicks or exits the wrapping canvas
            onmouseup: move |_| drag_state.stop_drag(),
            onmouseleave: move |_| drag_state.stop_drag(),
            {children}
        }
    }
}

