  "main.rs": "/// An idiomatic Rust approach to lexical analysis is often to use a state machine
/// over the character iterator. This scales safely, skips intermediate allocations,
/// and is heavily readable by avoiding complex iterator chaining for stateful logic.

pub fn tokenize(s: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();

    let mut in_single_quote = false;
    let mut in_token = false;

    for c in s.chars() {
        if in_single_quote {
            if c == '\'' {
                in_single_quote = false;
            } else {
                current_token.push(c);
            }
        } else {
            match c {
                '\'' => {
                    in_single_quote = true;
                    in_token = true;
                }
                c if c.is_whitespace() => {
                    if in_token {
                        // std::mem::take replaces `current_token` with an empty String 
                        // and returns the old one, avoiding `.clone()`.
                        tokens.push(std::mem::take(&mut current_token));
                        in_token = false;
                    }
                }
                _ => {
                    in_token = true;
                    current_token.push(c);
                }
            }
        }
    }

    // Don't forget the last token if the string didn't end with a whitespace
    if in_token {
        tokens.push(current_token);
    }

    tokens
}

fn main() {
    let tokens = tokenize(" 'one'  ' two  'three    four");

    println!("{} args:", tokens.len());
    for token in tokens {
        println!("<{}>", token);
    }
}
