/// Recursively checks if the `target` JSON value conforms to the `filter` JSON value.
pub fn matches_filter(target: &Value, filter: &Value) -> bool {
    match (target, filter) {
        // If both are objects, iterate over the filter's fields.
        (Value::Object(t_map), Value::Object(f_map)) => {
            for (k, f_val) in f_map {
                match t_map.get(k) {
                    Some(t_val) => {
                        // Recursively match nested objects
                        if !matches_filter(t_val, f_val) {
                            return false;
                        }
                    }
                    None => {
                        // If the target completely omitted a field but the filter asks for null,
                        // this is effectively a match. Otherwise fails.
                        if !f_val.is_null() {
                            return false;
                        }
                    }
                }
            }
            true
        }
        // If both are arrays, check exact lengths and zip their contents.
        (Value::Array(t_arr), Value::Array(f_arr)) => {
            if t_arr.len() != f_arr.len() {
                return false;
            }
            t_arr.iter().zip(f_arr).all(|(t, f)| matches_filter(t, f))
        }
        // For primitive types (numbers, string, bools, null) require exact equality.
        (t_val, f_val) => t_val == f_val,
    }
}

