    fn matches_json_filter(&self, filter: &Value) -> bool;
}

impl<T: Serialize> FilterMatch for T {
    fn matches_json_filter(&self, filter: &Value) -> bool {
        // By serializing the struct to a serde_json::Value, we easily unify all forms of 
        // Structs, Options, Enums and Defaults to a generic comparable format in pure Rust code.
        let serialized_target = serde_json::to_value(self)
            .expect("Failed to serialize struct for filter matching");

        matches_filter(&serialized_target, filter)
    }
}

