        // This gives us an entirely separate file handle to write to,
        // side-stepping the need to wrap `expectrl::Session` inside a global Mutex.
        let fd = session.as_raw_fd();
        let cloned_fd = unsafe { libc::dup(fd) };
        if cloned_fd < 0 {
            return Err("Failed to duplicate PTY file descriptor".into());
        }

        let writer = unsafe { File::from_raw_fd(cloned_fd) };
        let writer_arc = Arc::new(Mutex::new(writer));

