                        break;
                    }
                }
            }
        });

        Ok(Self { writer: writer_arc })
    }

    pub fn send(&self, data: &str) {
        // 3) Write directly to the duplicated file descriptor.
        // It locks ONLY the writer (which resolves instantaneously), completely 
        // bypassing the read thread's blocking `read()`.
        if let Ok(mut guard) = self.writer.lock() {
            let _ = guard.write_all(data.as_bytes());
            let _ = guard.flush();
        }
    }
}

