// Actually, returning a `Cow` *avoids* allocating Strings. `k8s/kube` standard resources
// just yield `Cow::Borrowed(&'static str)`, which acts exactly like a free `&'static str`!
// We can just implement `Hash` and `PartialEq` by leaning on these getters directly.

#[derive(Debug, Clone)]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    name: String,
}

impl<R: Resource> ResourceRef<R>
where
    R::DynamicType: Default,
{
    pub fn new(resource: R) -> Self {
        // Unwrapping the borrowed name, then handing it off below to create our internal String
        let name = resource.meta().name.as_deref().expect("Resource must have a name");
        Self::new_named(name)
    }

    pub fn new_named(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();

        Self {
            type_: PhantomData,
            dynamic_type,
            name: name.to_string(),
        }
    }

    // By deferring to getters, Rust happily borrows from `&self` instead of tying 
    // lifetimes up at object creation.
    pub fn group(&self) -> Option<Cow<'_, str>> {
        let group = R::group(&self.dynamic_type);
        if group.is_empty() {
            None
        } else {
            Some(group)
        }
    }

    pub fn kind(&self) -> Cow<'_, str> {
        R::kind(&self.dynamic_type)
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

// ---- Satisfying HashMap Key Requirements (Hash, PartialEq, Eq) ----

impl<R: Resource> PartialEq for ResourceRef<R>
where
    R::DynamicType: Default,
{
    fn eq(&self, other: &Self) -> bool {
        self.name == other.name 
            && self.group() == other.group() 
            && self.kind() == other.kind()
    }
}

impl<R: Resource> Eq for ResourceRef<R> where R::DynamicType: Default {}

impl<R: Resource> Hash for ResourceRef<R>
where
    R::DynamicType: Default,
{
    fn hash<H: Hasher>(&self, state: &mut H) {
        self.name.hash(state);
        self.group().hash(state);
        self.kind().hash(state);
    }
}

// ---- Runnable Executable / Tests ----

struct MockPod {
    meta: Meta,
}

impl Resource for MockPod {
    type DynamicType = ();

    fn group(_dt: &Self::DynamicType) -> Cow<'_, str> {
        Cow::Borrowed("core") // Evaluates as zero-allocation static str internally
    }

    fn kind(_dt: &Self::DynamicType) -> Cow<'_, str> {
        Cow::Borrowed("Pod")
    }

    fn meta(&self) -> &Meta {
        &self.meta
    }
}

fn main() {
    let pod = MockPod {
        meta: Meta {
            name: Some("my-pod".to_string()),
        },
    };

    // Creation works gracefully without hitting self-referential variable E0515 error.
    let ref1 = ResourceRef::new(pod);
    let ref2 = ResourceRef::<MockPod>::new_named("my-pod");

    // Validating HashMap / Eq mechanics implicitly trigger our deferred getters under the hood
    assert_eq!(ref1, ref2);

    let mut map = HashMap::new();
    map.insert(ref1, "Running");

    println!("HashMap Lookup Success! state: {:?}", map.get(&ref2));
}
"
}
