macro_rules! export_driver {
    (
        $vis:vis struct $name:ident;
    ) => {
        // 1. Output the original struct
        $vis struct $name;

        // 2. Output the exported C-callable function using the corrected unsafe macro syntax.
        #[unsafe(no_mangle)]
        pub unsafe extern "C" fn init() -> i32 {
            $name::init()
        }
    };
}

