  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};
use tokio::time::{sleep, Duration};

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// To call `poll` directly without an async context `Waker`, we construct a dummy no-op Waker.
/// This is perfectly safe: if the future is `Pending`, it registers this dummy waker.
/// Later, when we spawn it via tokio, it gets polled again with a REAL waker, and the 
/// future will drop the dummy waker and register the real tokio waker properly.
fn noop_waker() -> Waker {
    const VTABLE: RawWakerVTable = RawWakerVTable::new(
        |ptr| RawWaker::new(ptr, &VTABLE), // clone
        |_| {},                            // wake
        |_| {},                            // wake_by_ref
        |_| {},                            // drop
    );
    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

/// Notice we take `Pin<&mut F>`. You cannot safely poll an unpinned future directly 
/// unless it specifically implements `Unpin`.
fn try_poll<F: Future>(future: Pin<&mut F>) -> TryPollResult<F::Output> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    match future.poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// A synchronous non-async function executed from an async context
fn handle_future_sync<F>(future: F) 
where 
    F: Future<Output = String> + Send + 'static 
{
    // First, pin the future to the heap. 
    // This does 2 things: 
    // 1. Allows us to safely poll it.
    // 2. Gives us ownership of the allocated future so we can STILL spawn it if it is Pending.
    let mut pinned_future = Box::pin(future);

    // Use the custom manually implemented try_poll
    match try_poll(pinned_future.as_mut()) {
        TryPollResult::Ready(val) => {
            println!("  [Sync] Future was ready immediately: {}", val);
        }
        TryPollResult::Pending => {
            println!("  [Sync] Future is pending. Spawning to tokio background task...");
            tokio::spawn(async move {
                // pinned_future is `Box<Pin<F>>`, which implements Future itself.
                let val = pinned_future.await;
                println!("  [Async] Spawned task finished with: {}", val);
            });
        }
    }

    /* 
     * AS A SIDE NOTE:
     * You CAN actually use `now_or_never()` for this! 
     * The trick you missed is to call it on `pinned_future.as_mut()` instead of `future`.
     * This consumes the temporary pinned reference rather than the future itself, allowing 
     * you to still spawn the future later!
     * 
     * use futures::FutureExt;
     * match pinned_future.as_mut().now_or_never() {
     *     Some(val) => println!("Ready: {}", val),
     *     None => { tokio::spawn(pinned_future); }
     * }
     */
}

#[tokio::main]
async fn main() {
    println!("--- Passing an immediately ready future ---");
    // This will finish entirely synchronously inside `handle_future_sync`.
    handle_future_sync(std::future::ready("Hello Instant".to_string()));

    println!("\n--- Passing a future that requires awaiting ---");
    // This will evaluate the `sleep` future, see that it requires a real timer,
    // return Pending, and get appropriately passed off to tokio.
    handle_future_sync(async {
        sleep(Duration::from_millis(200)).await;
        "Hello Delayed".to_string()
