  "main.rs": "use nalgebra::DMatrix;

fn main() {
    let n = 4; // Number of observations (rows)
    let k = 3; // Number of features (columns)

    // Create an n x k matrix
    let matrix = DMatrix::from_row_slice(n, k, &[
        2.0,  5.0,  9.0,
        4.0,  7.0, 15.0,
        6.0,  9.0, 21.0,
        8.0, 11.0, 27.0,
    ]);

    println!("Original Matrix ({}x{}):", n, k);
    println!("{}", matrix);

    // =========================================================================
    // Approach 1: Out-of-Place (Conceptual Broadcasting via `from_fn`)
    // =========================================================================
    // Note: Instead of using `row_mean_tr()`, `column_mean()` correctly computes 
    // the mean of each column directly, yielding a 1 x k row vector.
    let means = matrix.column_mean();

    // `nalgebra` lacks implicit broadcasting (like Python's numpy), 
    // so we manually broadcast the row vector to all rows by mapping over the elements.
    let centered_out_of_place = DMatrix::from_fn(n, k, |row, col| {
        matrix[(row, col)] - means[(0, col)]
    });

    println!("Approach 1 - Centered (Out-of-Place):");
    println!("{}", centered_out_of_place);

    // =========================================================================
    // Approach 2: In-Place (Idiomatic & More Efficient)
    // =========================================================================
    // Mutating the matrix column-by-column using iterators avoids allocations 
    // and is highly performant.
    let mut centered_in_place = matrix.clone(); 

    for mut col in centered_in_place.column_iter_mut() {
        let col_mean = col.mean();
        // Subtract the scalar mean from every element in this column slice
        col.add_scalar_mut(-col_mean);
    }

    println!("Approach 2 - Centered (In-Place):");
    println!("{}", centered_in_place);

    // =========================================================================
    // Bonus: Computing the Covariance Matrix
    // =========================================================================
    // Covariance is (X^T * X) / (n - 1)
    let cov = (&centered_in_place.transpose() * &centered_in_place) / ((n - 1) as f64);
    println!("Resulting Covariance Matrix ({}x{}):", k, k);
    println!("{}", cov);
}
"
}

