{
  "Cargo.toml": "[package]
name = "design-dilemma-solution"
version = "0.1.0"
edition = "2021"

[dependencies]
ambassador = "0.4"
",
  "main.rs": "//! This self-contained project solves your dependency cycle dilemma.
//!
//! # The Dilemma
//! `enum_dispatch` requires the trait and enum to be in the same crate because 
//! procedural macros in Rust cannot natively see type definitions from other crates.
//! Integrating the abstract (`al`) and business (`bl`) layers to satisfy this 
//! requirement causes a cycle: `al` depends on `il` (for enum variant struct implementations),
//! and `il` depends on `al` (for the trait to implement).
//!
//! # The Solution
//! Use the `ambassador` crate. It was built exactly for this purpose: cross-crate 
//! zero-cost trait delegation.
//!
//! When you annotate a trait with `#[delegatable_trait]` in `al`, it generates 
//! a declarative `macro_rules!` under the hood. This declarative macro effortlessly 
//! traverses crate boundaries, delivering the 20+ method blueprint without cycles.
//!
//! - `al` defines the trait. (Depends on nothing)
//! - `il` implements the trait. (Depends on `al`)
//! - `bl` defines the enum and statically dispatches. (Depends on `al` and `il`)
//!
//! This provides identical static dispatch performance to `enum_dispatch` 
//! without manually typing out methods or compromising your layered architecture.

// ---------------------------------------------------------
// 1. Abstract Layer (al)
// ---------------------------------------------------------
pub mod al {
    use ambassador::delegatable_trait;

    // By tagging the trait, a declarative macro is generated and exported
    // making the trait delegate-able across crate boundaries.
    #[delegatable_trait]
    pub trait Rest {
        fn serve(&self) -> &'static str;
        fn port(&self) -> u16;
    }
}

// ---------------------------------------------------------
// 2. Implementation Layer (il)
// ---------------------------------------------------------
pub mod il {
    use crate::al::Rest;

    pub struct Foo;
    impl Rest for Foo {
        fn serve(&self) -> &'static str { "Serving from Foo" }
        fn port(&self) -> u16 { 8080 }
    }

    pub struct Boo;
    impl Rest for Boo {
        fn serve(&self) -> &'static str { "Serving from Boo" }
        fn port(&self) -> u16 { 9090 }
    }
}

// ---------------------------------------------------------
// 3. Business Layer (bl)
// ---------------------------------------------------------
pub mod bl {
    use crate::al::Rest;
    use crate::il::{Foo, Boo};
    use ambassador::Delegate;

    // Easily delegate trait implementation across boundaries.
    // Note: In your actual multi-crate architecture, you would use:
    // `#[delegate(al::Rest)]` assuming `al` is an imported crate.
    #[derive(Delegate)]
    #[delegate(Rest)]
    pub enum Item {
        // Just like `enum_dispatch`, variants should hold the concrete structs.
        Foo(Foo), 
        Boo(Boo),
    }
}

// ---------------------------------------------------------
// Entry point
// ---------------------------------------------------------
fn main() {
    use al::Rest;
    use bl::Item;
    use il::{Foo, Boo};

    let item1 = Item::Foo(Foo);
    let item2 = Item::Boo(Boo);

    // Demonstration of static dispatch working correctly!
    println!("Item 1: {} on port {}", item1.serve(), item1.port());
    println!("Item 2: {} on port {}", item2.serve(), item2.port());
}
"
}
