/// THE CORE ISSUE:
/// You tried to create a custom operator by defining a struct and implementing
/// a trait for it (`impl operation for sqrtplusone`). However, in Rust, genetic 
/// programming libraries like `radiate` do not use Traits to define operations. 
/// Instead, `Op` is a closed Enum. Because Enums are closed in Rust, you cannot
/// add new variants from outside the crate.
///
/// THE SOLUTION:
/// To solve your robot logic problem, you have two options with `radiate`:
/// 
/// Option 1: If `radiate` provides a closure constructor, use it to wrap your function.
/// ```rust
/// // Depending on the radiate release, something like this might be supported instead of a trait:
/// // let custom_op = Op::func("sqrtplusone", 1, std::sync::Arc::new(|args: &[f32]| args[0].sqrt() + 1.0));
/// ```
/// 
/// Option 2: Fork the `radiate` crate and add `SqrtPlusOne` into its `Op` enum natively, 
/// OR define a custom expression tree evaluator algorithm to generate equations for 
/// your small chip (as you mentioned a neural network is infeasible).
///
/// Below is a fully runnable example showing exactly how GP tree operators are 
/// evaluated under the hood, and how you can implement `SqrtPlusOne` algorithmically.

#[derive(Clone, Debug)]
pub enum CustomOp {
    Add,
    Sub,
    Mul,
    Pow,
    // We add your custom operator directly to the Operator Enum!
    SqrtPlusOne,
    // Variable reference (e.g., sensor inputs for the robot)
    Var(usize), 
}

impl CustomOp {
    /// Arity defines how many arguments the operation needs.
    /// `sqrt(x) + 1` takes exactly 1 argument.
    pub fn arity(&self) -> usize {
        match self {
            CustomOp::Add | CustomOp::Sub | CustomOp::Mul | CustomOp::Pow => 2,
            CustomOp::SqrtPlusOne => 1,
            CustomOp::Var(_) => 0,
        }
    }

    /// The literal execution logic for the robot's equation discovery
    pub fn apply(&self, args: &[f32], inputs: &[f32]) -> f32 {
        match self {
            CustomOp::Add => args[0] + args[1],
            CustomOp::Sub => args[0] - args[1],
            CustomOp::Mul => args[0] * args[1],
            CustomOp::Pow => args[0].powf(args[1]),

            // --- YOUR CUSTOM LOGIC IMPLEMENTATION ---
            CustomOp::SqrtPlusOne => args[0].sqrt() + 1.0,

            CustomOp::Var(idx) => inputs[*idx],
        }
    }
}

/// A genetic structure mirroring how trees are constructed in radiate:
#[derive(Debug)]
pub struct Node {
    pub op: CustomOp,
    pub children: Vec<Node>,
}

impl Node {
    /// Recursively evaluate the genetic tree against the robot's state (inputs).
    pub fn evaluate(&self, inputs: &[f32]) -> f32 {
        // Recursively evaluate children (sub-trees)
        let evaluated_args: Vec<f32> = self.children.iter().map(|c| c.evaluate(inputs)).collect();

        // Apply the operator logic to the evaluated children
        self.op.apply(&evaluated_args, inputs)
    }
}

fn main() {
    println!("--- Robot Logic Equation Discovery ---\n");

    // Simulating a parsed tree generated by your Genetic Program process.
    // Equation: SqrtPlusOne( Var(0) ) + Pow( Var(1), Var(2) )
    // Conceptually this is:  sqrt(sensor[0]) + 1.0 + (sensor[1] ^ sensor[2])

    let robot_logic_tree = Node {
        op: CustomOp::Add,
        children: vec![
            Node {
                op: CustomOp::SqrtPlusOne,
                children: vec![
                    Node { op: CustomOp::Var(0), children: vec![] } // Index 0 (e.g. x-axis)
                ]
            },
            Node {
                op: CustomOp::Pow,
                children: vec![
                    Node { op: CustomOp::Var(1), children: vec![] }, // Index 1
                    Node { op: CustomOp::Var(2), children: vec![] }, // Index 2
                ]
            }
        ]
    };

    // Suppose your robot feeds these sensor inputs:
    // Sensor 0 = 9.0
    // Sensor 1 = 2.0
    // Sensor 2 = 3.0
    let sensor_inputs = [9.0, 2.0, 3.0];

    // 1) sqrt(9.0) + 1.0 = 4.0
    // 2) 2.0 ^ 3.0 = 8.0
    // 3) 4.0 + 8.0 = 12.0
    let logic_result = robot_logic_tree.evaluate(&sensor_inputs);

    println!("Sensor Inputs: {:?}", sensor_inputs);
    println!("Evaluated Logic Result: {}", logic_result);
    assert_eq!(logic_result, 12.0);

    println!("\nSuccess! The custom SqrtPlusOne operator correctly evaluated without traits.");
    println!("\nTIP: If you continue to use `radiate` natively, clone their library to your PC, add `SqrtPlusOne` into `radiate/src/models/tree/op.rs` exactly like `CustomOp` works in this file, and point your Cargo.toml directly to your local folder!");
}
"
}
