pub struct Context(pub i32);

pub enum InnerAsyncEvent {
    DoWithContext {
        // Changed to `FnOnce` to align with the goal of processing something once (matching `AsyncFnOnce`).
        // A normal `Fn` closure cannot return an `async move { ... }` block if it captures and moves variables.
        block: Box<
            dyn for<'a> FnOnce(
