// for closures returning futures can be notoriously problematic. The trait `AsyncFnOnce`
// is currently only fully supported with very bleeding-edge async closures (Rust 1.85+).
//
// A macro avoids the `Send` bound and lifetime type-inference headaches completely.
// It behaves identically to your requested function at the call-site and perfectly
// hides all boilerplate (`Box::new`, `Box::pin`, etc.).
macro_rules! with_context_async {
    ($sender:expr, |$ctx:ident| $body:expr) => {
        let _ = $sender.send(InnerAsyncEvent::DoWithContext {
            block: Box::new(|$ctx| Box::pin($body)),
        });
    };
}

#[tokio::main]
async fn main() {
