    let capture_val = 15;
    with_context_async!(tx, |ctx| async move {
        ctx.0 += capture_val;
        println!("Second update. Value is now: {}", ctx.0);
    });

    // The spawned thread that consumes workloads
    let handle = tokio::spawn(async move {
        let mut ctx = Context(0);

        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    // Resolves and awaits the pinned task cleanly
                    block(&mut ctx).await;
                }
            }
        }
    });

