/// `BaseParser` takes `'src` as a trait parameter rather than a GAT. This allows
/// the parser's logic to completely decouple the underlying string's lifetime (`'src`) 
/// from the lifetime inherently tied to traversing the inputs (`'a`).
pub trait BaseParser<'src> {
    type InputToken: Clone + PartialEq + fmt::Display + 'src;
    /// `Input` is generic over `'a` so it can be called with short-lived local slices.
    type Input<'a>: ChumskyInput<'a, Token = Self::InputToken, Span = SimpleSpan> + 'a;
    type Output;

    fn parser<'a>() -> impl ChumskyParser<
        'a,
        Self::Input<'a>,
        Self::Output,
        extra::Err<Rich<'a, Self::InputToken, SimpleSpan>>,
    >;

    /// Perform the parsing within this layer
    fn parse_this<'a>(input: Self::Input<'a>) -> Result<Self::Output, Vec<String>> {
        Self::parser().parse(input).into_result().map_err(|errors| {
            // Any reference to the local slice `'a` is mapped to an owned String.
            errors
                .into_iter()
                .map(|e| e.to_string())
                .collect::<Vec<_>>()
        })
    }
}

pub trait BaseSliceParser<'src>: BaseParser<'src>
where
    // The critical piece! We specify an HRTB equality constraint ensuring
    // that for any parsing lifetime `'a`, the input type is a slice. Thus, the compiler
    // knows what `Self::Input<'local>` equates to.
    for<'a> Self: BaseParser<'src, Input<'a> = &'a [Self::InputToken]>,
{
    fn parse_this_owned(input: Vec<Self::InputToken>) -> Result<Self::Output, Vec<String>> {
        // Because of the HRTB trait bound above, `input.as_slice()` 
        // is perfectly known statically to match `Self::Input<'local>`.
        Self::parse_this(input.as_slice())
