use bevy::prelude::*;
use futures::io::{AsyncReadExt, AsyncSeekExt};
use std::collections::HashMap;
use std::path::{Path, PathBuf};
use std::sync::{Arc, RwLock};

/// A custom AssetReader that treats our .pack files like a filesystem. 
/// Crucially, this acts completely lazily – it caches the Table Of Contents (TOC)
/// across threads to avoid parsing it 3200 times, but streams out only the 
/// demanded section of bytes without loading the entire archive payload into memory.
#[derive(Clone)]
struct LazyArchiveReader {
    // Thread-safe cache keeping track of parsed TOC for `.pack` archives we encounter
    toc_cache: Arc<RwLock<HashMap<PathBuf, HashMap<String, (u64, u64)>>>>,
}

impl AssetReader for LazyArchiveReader {
    async fn read<'a>(
        &'a self,
        path: &'a Path,
    ) -> Result<Box<Reader<'a>>, AssetReaderError> {
        // Our custom paths will be structured like "lazywad://archive.pack/path/to/texture.png"
        let path_str = path.to_str().ok_or_else(|| AssetReaderError::NotFound(path.to_path_buf()))?;

        let mut parts = path_str.splitn(2, '/');
        let archive_name = parts.next().unwrap();
        let entry_name = parts.next().ok_or_else(|| AssetReaderError::NotFound(path.to_path_buf()))?;

        // The root folder Bevy expects is `assets/` 
        let full_archive_path = PathBuf::from("assets").join(archive_name);

        // 1. Try fetching the file's TOC from cache to prevent repetitive loading operations
        let toc = {
            let cache = self.toc_cache.read().unwrap();
            cache.get(&full_archive_path).cloned()
        };

        let toc = match toc {
            Some(cached) => cached,
            None => {
                 // 2. We don't have the TOC. So we perform a single small read across the archive header!
                let mut file = async_fs::File::open(&full_archive_path).await.map_err(AssetReaderError::from)?;
                let parsed_toc = read_entire_toc(&mut file).await.map_err(AssetReaderError::from)?;

                let mut cache = self.toc_cache.write().unwrap();
                cache.insert(full_archive_path.clone(), parsed_toc.clone());
                parsed_toc
            }
        };

        // 3. Locate the specific offset & length for the exact pixel/image buffer we need right now
        let &(offset, length) = toc.get(entry_name).ok_or_else(|| AssetReaderError::NotFound(path.to_path_buf()))?;

        // 4. Eagerly pull ONLY those specific sub-asset bytes into memory directly for Bevy's native Image Loader!
        let mut file = async_fs::File::open(&full_archive_path).await.map_err(AssetReaderError::from)?;
        file.seek(std::io::SeekFrom::Start(offset)).await.map_err(AssetReaderError::from)?;

        let mut buffer = vec![0; length as usize];
        file.read_exact(&mut buffer).await.map_err(AssetReaderError::from)?;

        // Standard library 'Cursor' seamlessly implements `futures::io::AsyncRead` / `AsyncSeek` when wrapped securely 
        let cursor = futures::io::Cursor::new(buffer);
        Ok(Box::new(cursor))
    }

    async fn read_meta<'a>(
        &'a self,
        path: &'a Path,
    ) -> Result<Box<Reader<'a>>, AssetReaderError> {
        Err(AssetReaderError::NotFound(path.to_path_buf()))
    }

    async fn read_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> Result<Box<PathStream>, AssetReaderError> {
        Err(AssetReaderError::NotFound(path.to_path_buf()))
    }

    async fn is_directory<'a>(&'a self, _path: &'a Path) -> Result<bool, AssetReaderError> {
        Ok(false)
    }
}

async fn read_entire_toc(file: &mut async_fs::File) -> std::io::Result<HashMap<String, (u64, u64)>> {
    file.seek(std::io::SeekFrom::Start(0)).await?;
    let mut num_entries_bytes = [0u8; 4];
    file.read_exact(&mut num_entries_bytes).await?;
    let num_entries = u32::from_le_bytes(num_entries_bytes);

    let mut toc = HashMap::new();
    for _ in 0..num_entries {
        let mut name_len_bytes = [0u8; 4];
        file.read_exact(&mut name_len_bytes).await?;
        let name_len = u32::from_le_bytes(name_len_bytes);

        let mut name_bytes = vec![0u8; name_len as usize];
        file.read_exact(&mut name_bytes).await?;
        let name = String::from_utf8(name_bytes)
            .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))?;

        let mut offset_bytes = [0u8; 8];
        file.read_exact(&mut offset_bytes).await?;
        let offset = u64::from_le_bytes(offset_bytes);

        let mut length_bytes = [0u8; 8];
        file.read_exact(&mut length_bytes).await?;
        let length = u64::from_le_bytes(length_bytes);

        toc.insert(name, (offset, length));
    }
    Ok(toc)
}

fn main() {
    create_dummy_pack_file();

    let reader_cache = Arc::new(RwLock::new(HashMap::new()));

    App::new()
        // Register the new protocol BEFORE DefaultPlugins are appended!
        .register_asset_source(
            "lazywad",
            AssetSource::build().with_reader(move || {
                Box::new(LazyArchiveReader {
                    toc_cache: reader_cache.clone(),
                })
            }),
        )
        .add_plugins(DefaultPlugins)
        .add_systems(Startup, setup)
        .run();
}

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    commands.spawn(Camera2dBundle::default());

    // Using our Custom protocol! Bevy will extract the trailing `.png` naturally to map it to the ImageLoader,
    // while simultaneously dispatching the request to our newly implemented lightweight reader!
    let texture_handle = asset_server.load("lazywad://data.pack/test_image.png");

    commands.spawn(SpriteBundle {
        texture: texture_handle,
        transform: Transform::from_scale(Vec3::splat(100.0)),
        ..default()
    });
}

/// Generates a tiny dummy compressed file format containing a functional 1x1 white pixel in PNG format.
/// App uses this natively to evaluate our custom loaded bytes on load.
fn create_dummy_pack_file() {
    use std::io::Write;
    let dir_path = std::path::Path::new("assets");
    let p = dir_path.join("data.pack");
    if p.exists() { return; }
    std::fs::create_dir_all(dir_path).unwrap();
    let mut f = std::fs::File::create(&p).unwrap();

    let png_data: &[u8] = &[
        137, 80, 78, 71, 13, 10, 26, 10, 0, 0, 0, 13, 73, 72, 68, 82, 0, 0, 0, 1, 0, 0, 0, 1, 8,
        2, 0, 0, 0, 144, 119, 83, 222, 0, 0, 0, 12, 73, 68, 65, 84, 8, 215, 99, 248, 255, 255, 63,
        0, 5, 254, 2, 254, 220, 204, 89, 231, 0, 0, 0, 0, 73, 69, 78, 68, 174, 66, 96, 130,
    ];

    let entries = [
        ("hello.txt", b"Hello from the lazy loaded pack file!".as_slice()),
        ("test_image.png", png_data),
    ];

    let mut header_size = 4;
    for (name, _) in &entries {
        header_size += 4 + name.len() as u64 + 8 + 8;
    }

    f.write_all(&(entries.len() as u32).to_le_bytes()).unwrap();

    let mut current_offset = header_size;
    for (name, data) in &entries {
        f.write_all(&(name.len() as u32).to_le_bytes()).unwrap();
        f.write_all(name.as_bytes()).unwrap();
        f.write_all(&current_offset.to_le_bytes()).unwrap();
        f.write_all(&(data.len() as u64).to_le_bytes()).unwrap();
        current_offset += data.len() as u64;
    }

    for (_, data) in &entries {
        f.write_all(data).unwrap();
    }
}
"
