// =====================================================================
// 1 & 2: PACKAGING THE SCRIPT & DETERMINING THE PATH
// =====================================================================
// `cargo install` solely installs the final executable binary. Loose files 
// like `script.py` are left behind under normal circumstances.
//
// To ship `script.py` seamlessly, we embed its contents directly into 
// the Rust binary at compile-time using the `include_str!` macro:
//
//     const PYTHON_SCRIPT: &str = include_str!("python/script.py");
//
// For this example to confidently run via your `cargo run` test without
// you needing to create the side-file first, we simulate the output 
// of `include_str!` below as a raw string:
const PYTHON_SCRIPT: &str = r#"
import sys

def main():
    print("Hello from the embedded Python script!")
    print(f"Arguments passed via Rust: {sys.argv[1:]}")

if __name__ == "__main__":
    main()
"#;

fn main() {
    // Extract any command-line arguments the user passed to our Rust program, 
    // skipping the first argument (the Rust binary's own path).
    let args: Vec<String> = env::args().skip(1).collect();

    // At runtime, we write the embedded script to a secure temporary file.
    // This solves the "filesystem path" problem: we generate a real path 
    // dynamically so the `python` process can easily parse it.
    let mut temp_script = NamedTempFile::new().expect("Failed to create temporary file");
    temp_script
        .write_all(PYTHON_SCRIPT.as_bytes())
        .expect("Failed to write script to temporary file");

    // Determine the Python interpreter command depending on the OS.
    let python_exec = if cfg!(target_os = "windows") {
        "python"
    } else {
        "python3"
    };

    // Invoke the python interpreter
    // Effectively executing: `python3 /tmp/.../script.py [args]`
    let status = Command::new(python_exec)
        .arg(temp_script.path()) // Provide the dynamic path to our generated python file
        .args(&args)             // Pass along any user arguments naturally
        .status()
        .expect("Failed to execute Python process. Ensure Python is installed.");

    // Transparently exit the Rust program with the script's exit code
    if !status.success() {
        exit(status.code().unwrap_or(1));
    }
}
"
}
