use tokio::sync::broadcast::{channel, Sender};
use tokio_stream::{Stream, StreamExt};
use tokio_stream::wrappers::BroadcastStream;
use tokio_util::sync::CancellationToken;

// Dummy Event wrapper to satisfy the example
#[derive(Debug, Clone, PartialEq)]
pub struct Event(pub String);

// Custom Error struct as implied by your snippet
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RecvError;

/// Instead of dropping all Senders (which is inherently difficult when they are cloned across the app),
/// the idiomatic approach in Tokio is to use a `CancellationToken`. We inject a cancellation token 
/// into the stream factory. When an interrupt occurs, we cancel the token, effectively dropping the,
/// `BroadcastStream` receivers natively which closes the SSE connections and allows the app to shut down gracefully.
pub fn events_channel() -> (EventSender, EventStreamFactory, CancellationToken) {
    let (tx, _) = channel(20);
    let token = CancellationToken::new();
    (
        EventSender { tx: tx.clone() },
        EventStreamFactory {
            tx,
            token: token.clone(),
        },
        token,
    )
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: Sender<Event>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }
}

pub struct EventStreamFactory {
    tx: Sender<Event>,
    token: CancellationToken,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, RecvError>> + Send {
        let token = self.token.clone();

        BroadcastStream::new(self.tx.subscribe())
            .filter_map(|event| match event {
                Ok(event) => Some(Ok(event)),
                Err(_) => Some(Err(RecvError)),
            })
            // The stream will yield `None` (terminating the SSE connection) when canceled.
            .take_until(async move {
                token.cancelled().await;
            })
    }
}

#[tokio::main]
async fn main() {
    // Setup channels and grab the cancellation token
    let (sender, factory, cancel_token) = events_channel();

    // 1. Simulate a Subscriber (e.g., an active SSE endpoint)
    let mut stream = Box::pin(factory.all_events());
    let sub_task = tokio::spawn(async move {
        let mut count = 0;
        while let Some(event) = stream.next().await {
            println!("Subscriber received: {:?}", event);
            count += 1;
        }
        println!("Subscriber stream ended cleanly. Total received: {}", count);
    });

    // 2. Simulate Senders generating events from all over your app
    let mut sender_tasks = vec![];
    for i in 1..=10 {
        let sender_clone = sender.clone();
        sender_tasks.push(tokio::spawn(async move {
            tokio::time::sleep(Duration::from_millis(i * 100)).await;
            sender_clone.send(Event(format!("App Event {}", i)));
        }));
    }

    // 3. Wait a moment to let some events emit
    tokio::time::sleep(Duration::from_millis(450)).await;

    // 4. INTERRUPT: Trigger a graceful shut down for the service
    println!("\n>>> Interrupt received! Shutting down SSE streams...\n");
    cancel_token.cancel();

    // 5. Await cleanup completion
    let _ = sub_task.await;
    for task in sender_tasks {
        let _ = task.await;
    }

