use std::collections::BTreeMap;

/// A completely flattened segment of an import path (e.g. `vexide::devices::smart`).
#[derive(Debug, Clone)]
struct FlatImport {
    path: Vec<String>,
    alias: Option<String>,
    is_star: bool,
}

/// A node representing our rebuilt import Tree (Trie logic).
#[derive(Default, Debug, Clone)]
struct TrieNode {
    /// Preserves alphabetical grouping similar to standard `rustfmt`
    children: BTreeMap<String, TrieNode>,
    alias: Option<String>,
    is_star: bool,
    is_terminal: bool,
}

impl TrieNode {
    fn insert(&mut self, import: FlatImport) {
        let mut current = self;
        for segment in import.path {
            current = current.children.entry(segment).or_default();
        }
        current.is_terminal = true;
        current.alias = import.alias;
        current.is_star = import.is_star;
    }
}

/// Rebuilds a perfectly valid and formatted Rust `Use` string.
fn format_trie(name: Option<&str>, node: &TrieNode) -> String {
    let mut res = String::new();
    if let Some(n) = name {
        res.push_str(n);
    }

    let mut internals = Vec::new();

    // If this specific module is imported AND its children are also imported,
    // we inject `self` so they can share the same braced group safely.
    if node.is_terminal && !node.children.is_empty() {
        if let Some(alias) = &node.alias {
            internals.push(format!("self as {}", alias));
        } else {
            internals.push("self".to_string());
        }
    }

    // Leaf node condition (No children)
    if node.is_terminal && node.children.is_empty() {
        if let Some(alias) = &node.alias {
            if res.is_empty() { return format!("self as {}", alias); }
            return format!("{} as {}", res, alias);
        } else if node.is_star {
            if res.is_empty() { return "*".to_string(); }
            return format!("{}::*", res);
        } else {
            return res;
        }
    }

    // Aggregate over children
    for (child_name, child_node) in &node.children {
        internals.push(format_trie(Some(child_name), child_node));
    }

    if internals.is_empty() {
        res
    } else if internals.len() == 1 && !node.is_terminal && res.is_empty() {
        internals.pop().unwrap()
    } else if internals.len() == 1 && !node.is_terminal {
        // Unnecessary to create braces if there's only 1 child and it isn't branching
        let inner = internals.pop().unwrap();
        if res.is_empty() {
            inner
        } else {
            format!("{}::{}", res, inner)
        }
    } else {
        if res.is_empty() {
            format!("{{{}}}", internals.join(", "))
        } else {
            format!("{}::{{{}}}", res, internals.join(", "))
        }
    }
}

/// Explodes an abstract syntax `UseTree` into flat arrays of import paths. 
fn flatten_use_tree(tree: &ast::UseTree, mut current_path: Vec<String>) -> Vec<FlatImport> {
    if let Some(p) = tree.path() {
        for segment in p.segments() {
            current_path.push(segment.to_string());
        }
    }

    let mut imports = Vec::new();
    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            imports.extend(flatten_use_tree(&child, current_path.clone()));
        }
    } else {
        // Automatically map trailing `self` segments into normalized module paths.
        // E.g., `vexide::devices::{self}` becomes `vexide::devices`
        if current_path.len() > 1 && current_path.last().map(|s| s.as_str()) == Some("self") {
            current_path.pop();
        }

        imports.push(FlatImport {
            path: current_path,
            alias: tree.rename().and_then(|r| r.name()).map(|n| n.to_string()),
            is_star: tree.star_token().is_some(),
        });
