// A synchronous callback loop inside RxRust mutably borrows Subjects' internal RefCells.
// This simple Trampoline scheduler pattern breaks the synchronicity by pushing tasks to a 
// queue that executes right after the current stack frame and its borrows are dropped.
fn enqueue(f: impl FnOnce() + 'static) {
    thread_local! {
        static QUEUE: RefCell<VecDeque<Box<dyn FnOnce()>>> = RefCell::new(VecDeque::new());
        static DRAINING: RefCell<bool> = RefCell::new(false);
    }

    QUEUE.with(|q| q.borrow_mut().push_back(Box::new(f)));
    DRAINING.with(|d| {
        if !*d.borrow() {
            *d.borrow_mut() = true;
            loop {
                // The borrow of QUEUE is strictly scoped tightly inside this line
                // so that executing the callback itself isn't locking the queue.
                let task = QUEUE.with(|q| q.borrow_mut().pop_front());
                match task {
                    Some(task) => task(),
                    None => break,
