// completely automatically using the `#[serde(from)]` attribute.
//
// This keeps your codebase perfectly clean: the helper is strictly an invisible intermediate 
// step, and you can deserialize directly into your `Character` struct in one step without 
// managing it in your application logic.

#[derive(Debug, PartialEq, Deserialize)]
#[serde(from = "CharacterJson")] // Tells Serde to automatically use our hidden shape
pub struct Character {
    pub name: String,
    pub ac: u8,
    pub current: u16,
    pub max: u16,
    pub temp: u16,
}

// We make this strictly private so it entirely stays out of your way and doesn't pollute
// your namespace. It accurately mirrors the JSON shape.
#[derive(Deserialize)]
struct CharacterJson {
    name: String,
    ac: u8,
    hp: u16,
}

// Serde runs this transparently every time you deserialize `Character`
impl From<CharacterJson> for Character {
    fn from(json: CharacterJson) -> Self {
        Self {
            name: json.name,
            ac: json.ac,
            current: json.hp,
            max: json.hp,
            temp: 0, // Gets effectively skipped and defaulted to 0
