name = "parallel_neighbors"
version = "0.1.0"
edition = "2021"

[dependencies]
rayon = "1.8"",
  "main.rs": "use rayon::prelude::*;

#[derive(Debug, Default, Clone)]
pub struct B {
    pub r: Vec<f64>,
    pub v: Vec<f64>,
    pub f: Vec<f64>,
    pub nb: Vec<usize>,
}

impl B {
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];

        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
pub struct A {
    pub elems: Vec<B>,
    pub cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    pub fn build_lists(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;

        // Borrow self.elems immutably to read across parallel tasks without unsafe 
        // or cloning the vectors.
        let elems = &self.elems;

        // 1 & 3: Safe parallel iteration using rayon, without copying B elements.
        // 2: Modify both elem_i and elem_j: we only test where i < j,
        // saving roughly ~50% of computations by evaluating each pair once.
        let pairs: Vec<(usize, usize)> = (0..nelems)
            .into_par_iter()
            .flat_map_iter(|i| {
                let elem_i = &elems[i];
                (i + 1..nelems).filter_map(move |j| {
                    if elem_i.criterion(&elems[j]) < cutoff {
                        Some((i, j))
                    } else {
                        None
                    }
                })
            })
            .collect();

        // Sequentially clear old lists, reusing capacities.
        for elem in self.elems.iter_mut() {
            elem.nb.clear();
        }

        // Apply symmetric relationship safely (modifies both elem_i and elem_j).
        for (i, j) in pairs {
            self.elems[i].nb.push(j);
            self.elems[j].nb.push(i);
        }
    }
}

fn main() {
    let mut a = A {
        elems: vec![
            B { r: vec![0.0, 0.0, 0.0], ..Default::default() },
            B { r: vec![1.0, 0.0, 0.0], ..Default::default() },
            B { r: vec![0.5, 0.0, 0.0], ..Default::default() },
            B { r: vec![5.0, 0.0, 0.0], ..Default::default() },
        ],
        cutoff: 2.0, // squared distance cutoff
    };

    a.build_lists();

    for (i, elem) in a.elems.iter().enumerate() {
        println!("Element {} neighbors: {:?}", i, elem.nb);
    }
}
"
}

