#[derive(Debug)]
enum Message {
    Signal(i32),
    Key(Key),
    Stop,
}

/// Listens for UNIX signals indefinitely unless a shutdown is triggered.
/// Returns a cleanly closeable handle to interrupt `signals.forever()` immediately.
fn yield_signals(sender: Sender<Message>) -> Handle {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).expect("Failed to create signal hook");

    // Obtain a handle so we can remotely close the iterator.
    let handle = signals.handle();

    thread::spawn(move || {
        // .forever() blocks until a signal arrives or it's closed via handle.
        for sig in signals.forever() {
            if sender.send(Message::Signal(sig)).is_err() {
                break;
            }
        }
    });

    handle
}

/// Listens to keys without blocking entirely, allowing us to check for manual stops.
fn yield_keys(sender: Sender<Message>, shutdown_rx: Receiver<()>) {
    thread::spawn(move || {
        // By using `async_stdin` instead of `stdin.lock()`, we avoid blocking the whole thread 
        // indefinitely on one read operation.
        let mut keys = termion::async_stdin().keys();

        loop {
            // 1. Check if the thread should finally return and stop gracefully
            if shutdown_rx.try_recv().is_ok() {
                break;
            }

            // 2. Safely read input non-blocking
            match keys.next() {
                Some(Ok(key)) => {
                    if sender.send(Message::Key(key)).is_err() {
                        break;
                    }
                }
                Some(Err(e)) if e.kind() == io::ErrorKind::WouldBlock => {
                    // If there's NO current key, sleep slightly to prevent high CPU usage 
                    // while preserving instant responsiveness.
                    thread::sleep(Duration::from_millis(15));
                }
                Some(Err(_)) => break,
                None => break,
            }
        }
    });
}

fn main() {
    let (sender, receiver) = mpsc::channel();
    let (shutdown_tx, shutdown_rx) = mpsc::channel::<()>();

    // Using `IntoRawMode` enables immediately reading characters without requiring the user to press Enter.
    // Keep it alive in `main` so it drops properly restoring terminal on exit.
    let _stdout = stdout().into_raw_mode().unwrap();

    // Spawning threads and retaining handles to terminate them forcefully but cleanly 
    let sig_handle = yield_signals(sender.clone());
    yield_keys(sender.clone(), shutdown_rx);

    // The Event Loop
    for msg in receiver.iter() {
        match msg {
            Message::Signal(sig) => {
                if sig == SIGINT || sig == SIGTERM {
                    println!("\r\nReceived termination signal: {}\r\n", sig);
                    break;
                }
            }
            Message::Key(Key::Char('q')) => {
