                let _ = sender.send(Message::Stop);
            }
            Message::Key(key) => {
                // Do arbitrary stuff based on other keys
                println!("\rPressed key: {:?}\r", key);
            }
            Message::Stop => {
                println!("\r\nStopping threads manually...\r\n");

                // Tell signal thread to release immediately without blocking
                sig_handle.close();

                // Tell keystroke thread to gracefully terminate
                let _ = shutdown_tx.send(());

                // Terminate main sequence 
                break;
            }
        }
    }
}
