  "main.rs": "/// Tokenizes a shell command string, respecting single-quoted strings.
///
/// In Rust, deep iterator chains (like map/flatten/group_by) can sometimes be
/// harder to read and less efficient than a straightforward state machine.
/// A simple `for` loop over characters is highly idiomatic for this kind of
/// string parsing task!
pub fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();

    // We maintain state as we iterate through characters.
    let mut in_quotes = false;
    let mut in_word = false;

    for c in input.chars() {
        match c {
            // Toggle quote state
            '\'' => {
                in_quotes = !in_quotes;
                in_word = true; // Quotes start a word even if it ends up empty (e.g., '')
            }
            // If we see whitespace and we are NOT inside quotes, the token ends
            c if c.is_ascii_whitespace() && !in_quotes => {
                if in_word {
                    // std::mem::take efficiently moves the built string into the vector
                    // and leaves an empty string in its place, avoiding .clone().
                    tokens.push(std::mem::take(&mut current_token));
                    in_word = false;
                }
            }
            // For any other character, or for spaces inside quotes, we append to the token
            _ => {
                in_word = true;
                current_token.push(c);
            }
        }
    }

    // Don't forget to push the final token if the string doesn't end with a space
    if in_word {
        tokens.push(current_token);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);

    println!("{} args:", tokens.len());
    for token in tokens {
        println!("<{}>", token);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_provided_example() {
        assert_eq!(
            tokenize(" one  ' two  'three    four"),
            vec!["one", " two  three", "four"]
        );
    }

    #[test]
    fn test_empty_string() {
        let expected: Vec<String> = vec![];
        assert_eq!(tokenize(""), expected);
        assert_eq!(tokenize("   "), expected);
    }

    #[test]
    fn test_empty_quotes() {
        assert_eq!(tokenize("''"), vec![""]);
        assert_eq!(tokenize("a '' b"), vec!["a", "", "b"]);
    }
}
