/// A globally available context to coordinate dragging state
/// without maintaining this data directly inside component props.
#[derive(Clone, Copy)]
pub struct DragState {
    // The currently dragged element's specific position Signal.
    // By holding a Signal emitted from the child itself, the parent
    // can update it directly, triggering re-render ONLY in that specific child.
    pub active_target: Signal<Option<Signal<(f64, f64)>>>,

    // The offset between the center of the point and the grab coordinates
    pub drag_offset: Signal<(f64, f64)>,
}

impl DragState {
    pub fn new() -> Self {
        Self {
            active_target: Signal::new(None),
            drag_offset: Signal::new((0.0, 0.0)),
        }
    }
}

pub fn app() -> Element {
    // Provide the DragState down to the component tree
    let mut drag_state = use_context_provider(|| DragState::new());

    rsx! {
        div {
            // Use touch-action: none and user-select: none to natively prevent selection tracking via CSS
            style: "width: 100vw; height: 100vh; touch-action: none; user-select: none; overflow: hidden;",

            onmousemove: move |me| {
                // Reading in an event listener DOES NOT trigger reactivity for `app`.
                // It effectively works as a peek.
                if let Some(mut pos_signal) = *drag_state.active_target.read() {
                    let coords = me.element_coordinates();
                    let offset = *drag_state.drag_offset.read();

                    // Mutating the child's signal here allows the specific `Point`
                    // to re-render independently. No global UI rebuild happens!
                    pos_signal.set((coords.x - offset.0, coords.y - offset.1));
                }
            },
            // Any release or drop-out clears the current target, regardless of where
            // the mouse currently resides.
            onmouseup: move |_| {
                if drag_state.active_target.read().is_some() {
                    drag_state.active_target.set(None);
                }
            },
            onmouseleave: move |_| {
                if drag_state.active_target.read().is_some() {
                    drag_state.active_target.set(None);
                }
            },

