    let mut drag_state = use_context::<DragState>();

    // Reading `active_target` here subscribes the point to drag start/stop events.
    // Since it's only modified in `mousedown` and `mouseup`, it will only trigger
    // at the very beginning and end of a movement, allowing us to change its stroke natively.
    let is_dragged = *drag_state.active_target.read() == Some(position);

    rsx! {
        circle {
            class: "point",
            // Read the individual positions, thus tracking the movement selectively.
            cx: "{position.read().0}",
            cy: "{position.read().1}",
            r: "{r}",
            fill: "{color}",
            cursor: if draggable { "grab" } else { "default" },
            stroke: if is_dragged { "#073B4C" } else { "none" },
