    // Since DMatrix is column-major by design, iterating and modifying it
    // column-by-column is the most cache-friendly and efficient approach as it
    // avoids allocating a second identical "broadcasted" matrix in memory.

    let mut centered_mut = matrix.clone();
    for mut col in centered_mut.column_iter_mut() {
        let col_mean = col.mean();
        col.add_scalar_mut(-col_mean);
    }

    println!("Centered matrix (Option 1 - In-place iterator):\n{}\n", centered_mut);


    // ------------------------------------------------------------------------
    // OPTION 2: Explicit matrix construction (Emulating broadcast)
    // ------------------------------------------------------------------------
    // If you explicitly want to calculate the `mean` row vector and subtract it,
    // you have to formulate a fully sized broadcast matrix manually.

    // Calculate the row vector of length k containing the mean of each column.
    // (In newer versions of nalgebra `matrix.row_mean()` performs this directly)
    let mean = RowDVector::from_iterator(
        matrix.ncols(),
