    println!("\n[Main] Ctrl+C received! Initiating graceful shutdown...");

    // 4. First, unblock and signal the queue handler to begin stopping
    queue_token.cancel();

    // 5. Signal the server to stop gracefully 
    // Passing `true` ensures it waits for active requests to close safely.
    server_handle.stop(true).await;

    // 6. Explicitly wait for both background tasks to fully resolve.
    // Without awaiting these, `main` returns immediately leaving ghost processes.
    let _ = queue_bg_task.await;
    let _ = server_bg_task.await;

    println!("[Main] All components shut down successfully. Exiting.");
    Ok(())
}
"
