{
  "Cargo.toml": "[package]
name = "kitty-shm-anim"
version = "0.1.0"
edition = "2021"

[dependencies]
libc = "0.2"
termion = "3.0"
ctrlc = "3.4"
",
  "main.rs": "use std::ffi::CString;
use std::io::{self, Write};
use std::ptr;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::time::{Duration, Instant};
use termion::terminal_size_pixels;

struct ShmBuffer {
    name: CString,
    name_str: String,
    size: usize,
    ptr: *mut u8,
    fd: libc::c_int,
}

impl ShmBuffer {
    fn new(name: &str, size: usize) -> Self {
        let name_c = CString::new(name).unwrap();
        unsafe {
            // Pre-emptively unlink in case it leaked from a previous crash
            libc::shm_unlink(name_c.as_ptr());

            let fd = libc::shm_open(
                name_c.as_ptr(),
                libc::O_CREAT | libc::O_RDWR,
                0o600,
            );
            if fd < 0 {
                panic!("Failed to shm_open {}", name);
            }
            if libc::ftruncate(fd, size as libc::off_t) < 0 {
                panic!("Failed to ftruncate {}", name);
            }
            let ptr = libc::mmap(
                ptr::null_mut(),
                size,
                libc::PROT_READ | libc::PROT_WRITE,
                libc::MAP_SHARED,
                fd,
                0,
            );
            if ptr == libc::MAP_FAILED {
                panic!("Failed to mmap {}", name);
            }
            Self {
                name: name_c,
                name_str: name.to_string(),
                size,
                ptr: ptr as *mut u8,
                fd,
            }
        }
    }

    fn name_str(&self) -> &str {
        &self.name_str
    }
}

impl Drop for ShmBuffer {
    fn drop(&mut self) {
        unsafe {
            libc::munmap(self.ptr as *mut libc::c_void, self.size);
            libc::close(self.fd);
            libc::shm_unlink(self.name.as_ptr());
        }
    }
}

fn main() {
    let running = Arc::new(AtomicBool::new(true));
    let run_clone = running.clone();
    ctrlc::set_handler(move || {
        run_clone.store(false, Ordering::SeqCst);
    }).expect("Error setting Ctrl-C handler");

    let stdout = io::stdout();
    let mut handle = stdout.lock();

    // Hide cursor and clear screen
    write!(handle, "\x1b[?25l\x1b[2J").unwrap();
    handle.flush().unwrap();

    let mut time: f32 = 0.0;

    let (width, height) = terminal_size_pixels().unwrap_or((640, 480));
    let (width, height) = (width as usize, height as usize);
    let size = width * height * 3;

    let pid = std::process::id();
    // Using a double-buffering approach prevents screen tearing 
    // that occurs if Kitty updates while we write to just one buffer.
    let name_a = format!("/kitty_anim_a_{}", pid);
    let name_b = format!("/kitty_anim_b_{}", pid);

    let mut buf_a = ShmBuffer::new(&name_a, size);
    let mut buf_b = ShmBuffer::new(&name_b, size);

    let mut use_a = true;
    let frame_duration = Duration::from_secs_f64(1.0 / 60.0);

    while running.load(Ordering::SeqCst) {
        let start_time = Instant::now();

        let current_buf = if use_a { &mut buf_a } else { &mut buf_b };
        let ptr = current_buf.ptr;

        // Render directly to mapped shared memory buffer bypassing Vec allocations
        for y in 0..height {
            let fy = y as f32 / height as f32;
            let g_base = fy * std::f32::consts::PI + time * 1.3;
            let g_val = ((g_base.sin() * 0.5 + 0.5) * 255.0) as u8;

            let b_phase_y = fy * std::f32::consts::PI + time * 0.7;

            for x in 0..width {
                let fx = x as f32 / width as f32;
                let r = ((fx * std::f32::consts::PI + time).sin() * 0.5 + 0.5) * 255.0;
                let b = ((fx * std::f32::consts::PI + b_phase_y).sin() * 0.5 + 0.5) * 255.0;

                let idx = (y * width + x) * 3;
                // Using unsafe to avoid bounds-checking overhead in this hot loop
                unsafe {
                    *ptr.add(idx) = r as u8;
                    *ptr.add(idx + 1) = g_val;
                    *ptr.add(idx + 2) = b as u8;
                }
            }
        }

        let shm_name = current_buf.name_str();

        // The `t=s` medium tells kitty to read from POSIX Shared Memory.
        // Using `i=1` binds it to an Image ID, preventing continuous placement of new images!
        // We don't have to chunk the output at all using shared memory. 
        write!(
            handle,
            "\x1b[H\x1b_Ga=T,f=24,s={},v={},t=s,i=1;{}\x1b\\",
            width, height, shm_name
        ).unwrap();
        handle.flush().unwrap();

        use_a = !use_a;
        time += 0.1;

        // Maintain exactly 60 FPS
        let elapsed = start_time.elapsed();
        if elapsed < frame_duration {
            std::thread::sleep(frame_duration - elapsed);
        }
    }

    // Delete all images and show cursor on exit
    write!(handle, "\x1b_Ga=d,d=A\x1b\\\x1b[?25h").unwrap();
    handle.flush().unwrap();
}
"
}

