  "main.rs": "use rustyline::error::ReadlineError;
use rustyline::DefaultEditor;
use std::io::{BufRead, BufReader};
use std::process::{Command, Stdio};
use std::thread;

fn main() -> rustyline::Result<()> {
    // 1. Initialize rustyline editor
    let mut rl = DefaultEditor::new()?;

    // 2. Create an external printer.
    // Rustyline provides this feature explicitly to solve the problem 
    // where `readline()` blocks on the main thread. It allows another 
    // thread to securely print to standard output without messing up 
    // the current prompt or the user's typed input.
    let mut printer = rl.create_external_printer()?;

    // 3. Spawn the child process
    // Here we use a mock shell command simulating a continuously 
    // outputting REPL returning async data.
    #[cfg(unix)]
    let mut child = Command::new("sh")
        .arg("-c")
        .arg("for i in 1 2 3 4 5; do sleep 3; echo \"[Child process async output $i]\" 1>&2; done")
        .stderr(Stdio::piped())
        .spawn()
        .expect("Failed to spawn child process");

    #[cfg(windows)]
    let mut child = Command::new("cmd")
        .arg("/c")
        .arg("for /L %i in (1,1,5) do @(ping 127.0.0.1 -n 4 > nul & echo [Child process async output %i] 1>&2)")
        .stderr(Stdio::piped())
        .spawn()
        .expect("Failed to spawn child process");

    // Using stderr or stdout depends on the REPL buffer settings. 
    // Commonly, stderr is unbuffered which is ideal for REPL interactions.
    let stderr = child.stderr.take().expect("Failed to capture stderr");

    // 4. Spawn a thread to consume the child process's output continuously
    thread::spawn(move || {
        let reader = BufReader::new(stderr);
        for line in reader.lines() {
            if let Ok(output_line) = line {
                // Print using the external printer instead of `println!`
                // It will neatly insert the text directly above your prompt!
                printer
                    .print(format!("{}\n", output_line))
                    .expect("Failed to print external message");
            }
        }
    });

    // 5. Main loop blocked strictly on readline
    loop {
        let readline = rl.readline("> ");
        match readline {
            Ok(line) => {
                let _ = rl.add_history_entry(line.as_str());
                println!("You sent: {}", line);
            }
            Err(ReadlineError::Interrupted) => {
                println!("CTRL-C");
                break;
            }
            Err(ReadlineError::Eof) => {
                println!("CTRL-D");
                break;
            }
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }

    Ok(())
}
