/// Generates a tiny test `.wad` file under `assets/archives/test.wad` 
/// so the demo can run in isolation and fetch lazy data.
fn create_test_archive() {
    let archives_dir = PathBuf::from("assets").join("archives");
    std::fs::create_dir_all(&archives_dir).unwrap();
    let archive_path = archives_dir.join("test.wad");

    let mut file = std::fs::File::create(&archive_path).unwrap();

    let files = vec![
        ("texture1.txt", b"MOCK TEXTURE 1 DATA LAZILY LOADED".to_vec()),
        ("texture2.txt", b"MOCK TEXTURE 2 DATA LAZILY LOADED".to_vec()),
    ];

    // Pre-allocate space for directory/header information
    file.seek(SeekFrom::Start(1024)).unwrap();

    let mut dir_entries = Vec::new();
    let mut current_offset = 1024;

    // Write body payloads arbitrarily down the file
    for (name, data) in files {
        file.write_all(&data).unwrap();
        dir_entries.push(format!("{}|{}|{}\n", name, current_offset, data.len()));
        current_offset += data.len() as u64;
    }

    // Come back to the start and record directory map (where everything is mapped)
    file.seek(SeekFrom::Start(0)).unwrap();
    for entry in dir_entries {
        file.write_all(entry.as_bytes()).unwrap();
    }
}

/// A custom `AssetReader` specifically built to handle our custom `wad://` 
/// source dynamically without eating up GBs of RAM.
struct WadAssetReader {
    base_path: PathBuf,
}

impl AssetReader for WadAssetReader {
    async fn read<'a>(&'a self, path: &'a Path) -> Result<Box<Reader<'a>>, AssetReaderError> {
        // Path provided by Bevy discards the asset source prefix. 
        // For `wad://archives/test.wad/texture1.txt`, path is `archives/test.wad/texture1.txt`
        let path_str = path.to_string_lossy();
        let parts: Vec<&str> = path_str.split(".wad/").collect();
        if parts.len() != 2 {
            return Err(AssetReaderError::NotFound(path.to_path_buf()));
        }

        // The base path is already the local path mapped by Bevy `assets` 
        // We reconnect it to standard OS filesystem capabilities 
        let archive_path = self.base_path.join(format!("{}.wad", parts[0]));
        let file_name = parts[1];

        let mut file = File::open(&archive_path)
            .map_err(|_| AssetReaderError::NotFound(archive_path.clone()))?;

        // Instead of processing the whole WAD, we just lightly process our index list chunk
        let mut dir_buffer = [0u8; 1024];
        file.read_exact(&mut dir_buffer)
            .map_err(|_| AssetReaderError::NotFound(path.to_path_buf()))?;

        let dir_str = String::from_utf8_lossy(&dir_buffer);
        let mut found_offset = 0;
        let mut found_len = 0;

        for line in dir_str.lines() {
            if line.is_empty() {
                continue;
            }
            let parts: Vec<&str> = line.split('|').collect();
            if parts.len() == 3 && parts[0] == file_name {
                found_offset = parts[1].parse().unwrap();
                found_len = parts[2].parse().unwrap();
                break;
            }
        }

        if found_len == 0 {
            return Err(AssetReaderError::NotFound(path.to_path_buf()));
        }

        // Seek to directly where the requested asset begins!
        // Natively satisfying chunk blocks lazily per requested file!
        file.seek(SeekFrom::Start(found_offset)).unwrap();
        let mut asset_data = vec![0; found_len as usize];
        file.read_exact(&mut asset_data).unwrap();

        // Return the chunk payload to Bevy loaders securely without blocking WAD IO open threads. 
        Ok(Box::new(Cursor::new(asset_data)))
    }

    async fn read_meta<'a>(&'a self, path: &'a Path) -> Result<Box<MetaReader<'a>>, AssetReaderError> {
        Err(AssetReaderError::NotFound(path.to_path_buf()))
    }

    async fn read_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> Result<Box<PathStream>, AssetReaderError> {
        Err(AssetReaderError::NotFound(path.to_path_buf()))
    }

    async fn is_directory<'a>(&'a self, _path: &'a Path) -> Result<bool, AssetReaderError> {
        Ok(false)
    }
