#[derive(Asset, TypePath, Debug)]
pub struct TextAsset(pub String);

#[derive(Default)]
pub struct TextAssetLoader;

// We write a simple fallback text loader so we can decode `.txt` files properly
impl AssetLoader for TextAssetLoader {
    type Asset = TextAsset;
    type Settings = ();
    type Error = std::io::Error;

    async fn load<'a>(
        &'a self,
        reader: &'a mut dyn Reader,
        _settings: &'a Self::Settings,
        _load_context: &'a mut LoadContext<'_>,
    ) -> Result<Self::Asset, Self::Error> {
        let mut bytes = Vec::new();
        reader.read_to_end(&mut bytes).await?;
        let text = String::from_utf8(bytes)
            .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))?;
        Ok(TextAsset(text))
    }

    fn extensions(&self) -> &[&str] {
        &["txt"]
    }
}

#[derive(Resource)]
struct MyAsset(Handle<TextAsset>);

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    // Here our WAD custom asset source automatically fires our custom LazyAssetReader mapping hook,
    // while simultaneously utilizing Standard Asset Loaders inherently because `texture1.txt` extension defaults to handling loader.
    let handle = asset_server.load("wad://archives/test.wad/texture1.txt");
    commands.insert_resource(MyAsset(handle));
}

fn print_text(
    my_asset: Res<MyAsset>,
    text_assets: Res<Assets<TextAsset>>,
    mut text_printed: Local<bool>,
    mut exit: EventWriter<AppExit>,
) {
    if *text_printed {
        return;
    }

    if let Some(text) = text_assets.get(&my_asset.0) {
        println!("Successfully loaded from lazy WAD reader!\nText inside: '{}'", text.0);
        *text_printed = true;
        exit.send(AppExit::Success);
    }
}

fn main() {
    // Initialize files to avoid boilerplate user errors while executing 
    create_test_archive();

    // Establish default bevy relative system directory configurations
    let base_path = std::env::current_dir().unwrap().join("assets");

    App::new()
        .register_asset_source(
            "wad",
            AssetSourceBuilder::default().with_reader(move || {
                Box::new(WadAssetReader {
                    base_path: base_path.clone(),
                })
            }),
        )
        .add_plugins(DefaultPlugins)
        .init_asset::<TextAsset>()
        .register_asset_loader(TextAssetLoader)
        .add_systems(Startup, setup)
        .add_systems(Update, print_text)
        .run();
}
"
