/// A macro that reduces all duplicated template code. 
/// In Rust, generic structures like `Vec<T>` inside dynamic (`dyn Any`) structures cannot 
/// be uniformly or openly downcasted at runtime statically because `Vec<String>` and `Vec<i32>` 
/// are completely distinct concrete types under the hood. 
/// 
/// The idiomatic solution without reflection libs is enumerating the components with a macro.
macro_rules! auto_downcast {
    ($value:expr, $ui:expr, $title:expr, $interactable:expr, [ $( ($t:ty, $func:ident) ),* $(,)? ]) => {
        $(
            if let Some(v) = $value.downcast_mut::<$t>() {
                $func($ui, $title, v, $interactable);
                return;
