    if downcast_all_enum_properties(value_mut, ui, title, interactable, true) {
        return;
    }

    // 2. Run the auto downcaster!
    // Simply add any primitive or basic datatype struct you have here, and it will automatically 
    // handle generic T, Vec<T>, and Option<T> natively in `std::any` downcasting.
    auto_downcast!(value_mut, ui, title, interactable, [
        (String, string_property),
        (i32, i_property),
        (f32, f_property),
        (usize, usize_property),
        (bool, bool_property),
        (NamedTypeValue, namedvalue_property),
        (ArgumentNamedValue, argnamedvalue_property),
        (DataType, datatype_property),
        (ValueType, valuetype_property),
    ]);

    // 3. Unhandled Fallback
    ui.label(
        RichText::new(format!("Field {}: unknown type", title))
        .color(Color32::LIGHT_RED)
    );
}

