    fn arity(&self) -> usize;
    fn evaluate(&self, args: &[f32], vars: &[f32]) -> f32;
}

// Boilerplate trick in Rust to allow dynamically-sized traits (`Box<dyn Trait>`) to be Cloned.
pub trait SystemClone {
    fn clone_box(&self) -> Box<dyn Operation>;
}

impl<T> SystemClone for T
where
    T: Operation + Clone + 'static,
{
    fn clone_box(&self) -> Box<dyn Operation> {
        Box::new(self.clone())
    }
}

