// --------------------------------------------------------------------------------------

#[derive(Debug, Clone)]
pub struct SqrtPlusOne;

impl Operation for SqrtPlusOne {
    fn arity(&self) -> usize {
        1 // Takes exactly 1 child argument
    }

    fn evaluate(&self, args: &[f32], _vars: &[f32]) -> f32 {
        // args[0] is the resolved internal result of the child node!
        if args[0] < 0.0 {
            0.0 // Protect against invalid math bounds on small chips
        } else {
            args[0].sqrt() + 1.0_f32
        }
    }
}

#[derive(Debug, Clone)]
pub struct Add;

impl Operation for Add {
    fn arity(&self) -> usize {
        2 // Takes 2 arguments
    }

    fn evaluate(&self, args: &[f32], _vars: &[f32]) -> f32 {
        args[0] + args[1]
    }
}

#[derive(Debug, Clone)]
pub struct Var(pub usize);

impl Operation for Var {
    fn arity(&self) -> usize {
        0 // Variables are leaves (0 arguments)
    }

    fn evaluate(&self, _args: &[f32], vars: &[f32]) -> f32 {
