    /// Recursively evaluates the equation matching your robot's logic
    pub fn evaluate(&self, vars: &[f32]) -> f32 {
        match self {
            Node::Val(v) => *v,
            Node::Op(op, children) => {
                let evaluated_args: Vec<f32> = children.iter().map(|c| c.evaluate(vars)).collect();
                op.evaluate(&evaluated_args, vars)
            }
