fn get_segments(tree: &ast::UseTree, prefix: &[String], out: &mut Vec<SegmentInfo>) {
    let mut current_prefix = prefix.to_vec();

    // 1. Traverse a multi-segment `Path` root-to-leaf.
    if let Some(path) = tree.path() {
        let mut path_nodes = Vec::new();
        let mut curr = Some(path.clone());
        while let Some(p) = curr {
            path_nodes.push(p.clone());
            curr = p.qualifier();
