                let seg_name = seg.syntax().text().to_string().trim().to_string();
                current_prefix.push(seg_name.clone());

                out.push(SegmentInfo {
                    segment_node: seg.clone(),
                    absolute_path: current_prefix.clone(),
                });
            }
        }
    }

    // 2. Dive into nested list elements.
    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            get_segments(&child, &current_prefix, out);
        }
    }
}

