    let root = parse.tree().syntax().clone();

    let mut edits = Vec::new();

    // Find every `use` item in the AST
    for use_item in root.descendants().filter_map(ast::Use::cast) {
        if let Some(tree) = use_item.use_tree() {
            let mut segments = Vec::new();
            get_segments(&tree, &[], &mut segments);

            for info in segments {
                let path_len = info.absolute_path.len();
                // Identify nodes resolving explicitly to `...::vexide::devices`
                if path_len >= 2 
                    && info.absolute_path[path_len - 2] == "vexide"
                    && info.absolute_path[path_len - 1] == "devices" 
                {
                    let seg_node = info.segment_node.clone();
                    let p = seg_node.syntax().parent().and_then(ast::Path::cast).unwrap();

                    // CASE A: The `Path` we matched is a qualifier for a downstream path.
                    // e.g., `vexide::devices::smart` -> we remove `devices::`.
                    if let Some(parent_p) = p.syntax().parent().and_then(ast::Path::cast) {
                        if parent_p.qualifier().map(|it| it.syntax().clone()) == Some(p.syntax().clone()) {
                            let colon_colon = parent_p.syntax().children_with_tokens()
                                .find(|it| it.kind() == SyntaxKind::COLONCOLON);
                            if let Some(cc) = colon_colon {
                                edits.push(Edit {
                                    range: TextRange::new(seg_node.syntax().text_range().start(), cc.text_range().end()),
                                    replacement: "".to_string(),
                                });
                            }
                            continue;
                        }
