                    // CASE B, C, D: The path is at the end of its path segment but directly inside a `UseTree` bounds.
                    if let Some(parent_tree) = p.syntax().parent().and_then(ast::UseTree::cast) {
                        if parent_tree.path().map(|it| it.syntax().clone()) == Some(p.syntax().clone()) {
                            let has_list = parent_tree.use_tree_list().is_some();
                            let has_star = parent_tree.star_token().is_some();

                            // CASE B: Has a list or star. `vexide::devices::{smart}` or `vexide::devices::*`.
                            // We delete `devices::` leaving just the scope bracket or `*` token.
                            if has_list || has_star {
                                let colon_colon = parent_tree.syntax().children_with_tokens()
                                    .find(|it| it.kind() == SyntaxKind::COLONCOLON);
                                if let Some(cc) = colon_colon {
                                    edits.push(Edit {
                                        range: TextRange::new(seg_node.syntax().text_range().start(), cc.text_range().end()),
                                        replacement: "".to_string(),
                                    });
                                    continue;
                                }
                            }

                            // CASE C & D: Target is an end-of-chain path segment.
                            if p.qualifier().is_some() {
                                // CASE C: It has a known prefix prior, `use vexide::devices;` 
                                // -> Strip backward including `::` to just leave `use vexide;`
                                let colon_colon = p.syntax().children_with_tokens()
                                    .find(|it| it.kind() == SyntaxKind::COLONCOLON);
                                if let Some(cc) = colon_colon {
                                    edits.push(Edit {
                                        range: TextRange::new(cc.text_range().start(), seg_node.syntax().text_range().end()),
                                        replacement: "".to_string(),
                                    });
                                }
                            } else {
                                // CASE D: Isolated completely (inside bracket), e.g. `use vexide::{devices};`.
                                // Swap to `{self}` so formatting/validity isn't broken leaving `{}` empty.
