//! You asked: "I feel that Ordering I've used is not correct. What is the correct Ordering and why?"
//!
//! ANSWER:
//! `Ordering::Relaxed` is 100% correct in this context.
//!
//! WHY:
//! 1. Mutual Exclusion: `critical_section::with` provides mutual exclusion. On the RP2040, this 
//!    translates to disabling interrupts and utilizing a hardware spinlock across its 2 Cortex-M0+ cores. 
//!    Because the code block runs without preemption or concurrent execution, no data races can occur 
//!    between the `load` and `store`. 
//! 2. Memory Barriers implicitly provided: The `critical-section` implementation already emits the 
//!    appropriate hardware memory barriers when acquiring and releasing the lock/interrupts. You do not 
//!    need stronger atomic orderings (like `Acquire` or `Release`) inside the block itself.
//! 3. Hardware Support: `thumbv6m` does not have hardware support for atomic CAS / `fetch_add`, 
//!    but it DOES support aligned 32-bit atomic load and store. `Relaxed` compiles directly to ordinary 
//!    `LDR` and `STR` instructions without unnecessary and expensive `DMB` instructions.
//!
//! PRO TIP: 
//! If `self.channel_index` is *only* ever read and written to inside of `critical_section::with` 
//! closures, you don't even need `AtomicUsize`. You can just use `core::cell::Cell<usize>`.
//! You should only keep `AtomicUsize` if you plan to do a lock-free `load` *outside* of the 
//! critical section.

use core::sync::atomic::{AtomicUsize, Ordering};

pub struct State {
    channel_index: AtomicUsize,
}

impl State {
    pub const fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Safely replacing `fetch_add` using a critical section and standard atomic load/store
    pub fn fetch_add(&self) -> usize {
        critical_section::with(|_| {
            let old_val = self.channel_index.load(Ordering::Relaxed);
            self.channel_index.store(old_val + 1, Ordering::Relaxed);
            old_val
        })
    }

    /// Lock-free load outside of critical section perfectly legal since values are stored atomically
    pub fn load_index(&self) -> usize {
        self.channel_index.load(Ordering::Relaxed)
    }
}

fn main() {
    let state = State::new();

    let i1 = state.fetch_add();
    let i2 = state.fetch_add();
    let i3 = state.fetch_add();

