use std::pin::Pin;
use std::task::{Context, Poll};

pub enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Polls a future synchronously without awaiting.
///
/// We require `Unpin` because if the future returns `Pending`,
/// the caller intends to move it into another task (`tokio::spawn`).
/// You cannot safely move a `!Unpin` future (like standard `async {}` blocks)
/// after it has been polled! The safe and standard way around this is
/// to heap-allocate the future using `Box::pin(future)`, yielding a
/// `Pin<Box<F>>` which implements both `Unpin` and `Future`.
pub fn try_poll<F>(future: &mut F) -> TryPollResult<F::Output>
where
    F: Future + Unpin,
{
    // It's perfectly safe and correct to use a noop_waker here.
    // If the future isn't ready and performs I/O, it registers the noop waker.
    // However, because you immediately spawn the future using `tokio::spawn`,
    // it will be polled *again* by Tokio with Tokio's REAL waker.
    // The I/O reactor will automatically register the new real waker, overwriting the noop waker.
    let waker = noop_waker_ref();
    let mut cx = Context::from_waker(waker);

    // Because `F` is `Unpin`, we can safely construct a `Pin` from a mutable reference.
    match Pin::new(future).poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// =========================================================
// Example Usage (Non-Async function called in Async context)
// =========================================================

pub fn evaluate_future_sync<F>(future: F)
where
    F: Future<Output = String> + Send + 'static,
{
    // 1. Box and pin the future to the heap.
    // This gives us a `Pin<Box<F>>`, which acts as an `Unpin` future!
    // We securely poll it by mutable reference, and later, move its ownership without UB.
    let mut boxed_future = Box::pin(future);

    // 2. We pass a mutable reference of our unpin future to try_poll.
    match try_poll(&mut boxed_future) {
        TryPollResult::Ready(val) => {
            println!("✔️  Future was immediately ready! Result: {}", val);
        }
        TryPollResult::Pending => {
            // 3. Since we didn't consume `boxed_future` and it is safely unpinned,
            // we freely move it into a new Tokio task.
            println!("⏳  Future is pending, spawning to tokio background task...");
            tokio::spawn(async move {
                let val = boxed_future.await;
                println!("🚀  Future completed in background! Result: {}", val);
            });
        }
    }
}

