/// to `op` (which often contains spaces and newlines from GraphQL/SQL), the Datadog
/// Agent parses the newline as the end of the metric, considering the first half malformed
/// and silently dropping it (which is why neither UDP nor UDS raised errors, but dashboards were empty).
fn sanitize_tag(value: &str) -> String {
