  "main.rs": "use std::sync::{Arc, Mutex};
use std::time::Duration;
use tokio::sync::broadcast::{channel, Sender};
use tokio_stream::{Stream, StreamExt};
use tokio_stream::wrappers::BroadcastStream;

#[derive(Debug, Clone)]
pub struct Event {
    pub data: String,
}

#[derive(Debug, Clone)]
pub struct RecvError;

pub fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = channel(20);
    // By wrapping the Sender in an Arc<Mutex<Option<Sender>>>, we can share 
    // a SINGLE clone of the actual Sender across our whole app. 
    let shared_tx = Arc::new(Mutex::new(Some(tx)));
    (
        EventSender { tx: shared_tx.clone() },
        EventStreamFactory { tx: shared_tx },
    )
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: Arc<Mutex<Option<Sender<Event>>>>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        // Only send if the inner Sender hasn't been dropped
        if let Some(tx) = self.tx.lock().unwrap().as_ref() {
            let _ = tx.send(event);
        }
    }

    /// Taking the Sender out of the Option drops the only instance of it. 
    /// This forcefully disconnects all receivers and cleanly terminates the streams.
    pub fn shutdown(&self) {
        let _ = self.tx.lock().unwrap().take();
    }
}

#[derive(Clone)]
pub struct EventStreamFactory {
    tx: Arc<Mutex<Option<Sender<Event>>>>,
}

impl EventStreamFactory {
    // Note: We use 'static instead of `use<>` because we are no longer capturing `&self`.
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, RecvError>> + Send + 'static {
        let rx = match self.tx.lock().unwrap().as_ref() {
            Some(tx) => tx.subscribe(),
            None => {
                // If the channel is already shut down, we create a dummy channel
                // and immediately drop the sender so the stream cleanly ends straight away.
                let (dummy_tx, rx) = channel(1);
                drop(dummy_tx);
                rx
            }
        };

        BroadcastStream::new(rx).filter_map(|event| match event {
            Ok(event) => Some(Ok(event)),
            Err(_) => Some(Err(RecvError)), // Maps BroadcastStreamRecvError::Lagged
        })
    }
}

#[tokio::main]
async fn main() {
    let (sender, factory) = events_channel();

    // 1. Create our stream to mimic SSE subscription
    let mut stream = Box::pin(factory.all_events());

    // 2. Spawn a background task simulating an independent system feeding data,
    // demonstrating that the EventSender can be cloned safely.
    let sender_clone = sender.clone();
    tokio::spawn(async move {
        let mut count = 0;
        loop {
            tokio::time::sleep(Duration::from_millis(150)).await;
            sender_clone.send(Event {
                data: format!("Message {}", count),
            });
            count += 1;
        }
    });

    // 3. Spawn a task to listen to the events (representing the SSE client)
    let listener = tokio::spawn(async move {
        println!("Listener task started...");
        while let Some(event) = stream.next().await {
            match event {
                Ok(e) => println!("Received matching event: {}", e.data),
                Err(_) => println!("Received an error (stream lagged)"),
            }
        }
        println!("\nListener task successfully stopped because the stream gracefully closed.");
    });

    // 4. Let the system run for a bit, then simulate an interrupt to shutdown.
    tokio::time::sleep(Duration::from_millis(500)).await;
    println!("\n--- Interrupt received! Executing explicit shutdown. ---");

    // Calling shutdown on ANY instance of the sender wipes the inner sender and kills the streams.
    sender.shutdown();

    // Block waiting for listener to gracefully exit
    let _ = listener.await;
}"
}
