fn ray_aabb(ray_origin: Vec3, ray_dir: Vec3, min: Vec3, max: Vec3) -> Option<(f32, Vec3)> {
    let mut tmin = f32::MIN;
    let mut tmax = f32::MAX;
    let mut normal = Vec3::Y;

    for i in 0..3 {
        let inv_d = 1.0 / ray_dir[i];
        let mut t0 = (min[i] - ray_origin[i]) * inv_d;
        let mut t1 = (max[i] - ray_origin[i]) * inv_d;
        let mut n0 = Vec3::ZERO; n0[i] = -1.0;
        let mut n1 = Vec3::ZERO; n1[i] = 1.0;

        if inv_d < 0.0 {
            std::mem::swap(&mut t0, &mut t1);
            std::mem::swap(&mut n0, &mut n1);
        }

        if t0 > tmin {
            tmin = t0;
            normal = n0;
        }
        tmax = tmax.min(t1);

        if tmax <= tmin {
            return None;
        }
    }

