#[derive(Default, Debug, PartialEq)]
struct A {
    x: usize,
    b: Vec<B>,
}

// We can use derive for B, or manually implement Deserialize for it as well.
// As long as it implements `Deserialize`, it bridges natively into A.
#[derive(Debug, PartialEq, Deserialize)]
enum B {
    Variant1,
    Variant2,
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct A")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut val = A::default();

                // FIX FOR RUN-TIME ERROR:
                // Using `<&str>` fails when the string contains escape sequences, or when
                // deserialize doesn't support zero-copy borrows (e.g. from an io::Read).
                // Resolving to `<String>` or `std::borrow::Cow<'de, str>` fixes the runtime error.
                while let Some(key) = map.next_key::<String>()? {
                    match key.as_str() {
                        "x" => val.x = map.next_value()?,

                        // FIX FOR The `????`:
                        // Since `B` implements `Deserialize`, Serde inherently knows how to 
                        // deserialize standard collections like `Vec<B>`. You literally just
                        // call `map.next_value()?` exactly like you did for `x`.
                        "b" => val.b = map.next_value()?,

                        _ => {
                            // Safely ignore unknown fields
                            let _ = map.next_value::<de::IgnoredAny>()?;
                        }
                    }
                }
                Ok(val)
            }
        }

        const FIELDS: &'static [&'static str] = &["x", "b"];
        deserializer.deserialize_struct("A", FIELDS, AVisitor)
    }
}

fn main() {
    let json_data = r#"
    {
        "x": 42,
        "b": ["Variant1", "Variant2", "Variant1"],
        "unknown_field": "Gets safely ignored"
    }
    "#;

    let result: A = serde_json::from_str(json_data).expect("Failed to deserialize");

    println!("{:#?}", result);

    assert_eq!(result.x, 42);
    assert_eq!(result.b, vec![B::Variant1, B::Variant2, B::Variant1]);

    println!("\nSuccessfully deserialized nested custom structures!");
}
"
}

