/// Recursively searches for `{"$ref": "..."}` objects in the JSON Value
/// and replaces them with the resolved content from disk.
fn resolve_refs(value: &mut Value, base_dir: &Path) {
    let mut resolved = None;

    match value {
        Value::Object(map) => {
            // Check if this object is a reference
            if let Some(Value::String(ref_str)) = map.get("$ref") {
                let parts: Vec<&str> = ref_str.splitn(2, '#').collect();
                let file_path = parts[0];
                let pointer = if parts.len() > 1 { parts[1] } else { "" };

                if file_path.is_empty() {
                    panic!("Internal references (starting with '#') are not supported in this basic example");
                }

                let target_path = base_dir.join(file_path);
                let json_data = fs::read_to_string(&target_path)
                    .unwrap_or_else(|_| panic!("failed to read ref file: {}", target_path.display()));

                let mut ref_val: Value = serde_json::from_str(&json_data)
                    .unwrap_or_else(|_| panic!("failed to parse ref file: {}", target_path.display()));

                // Standard JSON pointers start with '/'
                if !pointer.is_empty() {
                    ref_val = ref_val
                        .pointer(pointer)
                        .unwrap_or_else(|| panic!("pointer '{}' not found in {}", pointer, target_path.display()))
                        .clone();
                }

                // Recursively resolve references in the newly loaded file
                let new_base = target_path.parent().unwrap_or_else(|| Path::new(""));
                resolve_refs(&mut ref_val, new_base);

                resolved = Some(ref_val);
            } else {
                // Iterate standard map contents
                for v in map.values_mut() {
                    resolve_refs(v, base_dir);
                }
            }
        }
        Value::Array(arr) => {
            for v in arr.iter_mut() {
                resolve_refs(v, base_dir);
            }
        }
        _ => {}
    }

    if let Some(new_val) = resolved {
        *value = new_val;
    }
