  "main.rs": "use std::mem;

/// Splits a shell command string into tokens, respecting single quotes.
///
/// While it is possible to use functional combinations (`group_by`, `map`, `flat_map`, etc.),
/// idiomatic and modern Rust often approaches string tokenization with an imperative
/// state-machine loop over the `chars()`. This avoids multiple intermediate allocations,
/// reads directly as a single `O(n)` traversal, and is much simpler to debug and extend.
pub fn tokenize(s: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_quotes = false;
    let mut has_token = false;

    for c in s.chars() {
        match c {
            '\'' => {
                // Toggle the quote state.
                in_quotes = !in_quotes;
                // Even an empty string inside quotes `""` or `''` is a valid token.
                has_token = true;
            }
            ' ' if !in_quotes => {
                // Unquoted whitespace signifies a token boundary.
                if has_token {
                    // `mem::take` leaves an empty string in `current_token` without
                    // dropping the reused capacity, making it fast and idiomatic.
                    tokens.push(mem::take(&mut current_token));
                    has_token = false;
                }
            }
            _ => {
                // Any other character is pushed to the current active token.
                current_token.push(c);
                has_token = true;
            }
        }
    }

    // Do not forget to push the final token if we ended mid-token
    if has_token {
        tokens.push(current_token);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);

    println!("{} args:", tokens.len());
    for token in tokens {
        println!("<{}>", token);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_tokenize() {
        let expected = vec!["one", " two  three", "four"];
        assert_eq!(tokenize(" one  ' two  'three    four"), expected);
        assert_eq!(tokenize(" 'one'  ' two  'three    four"), expected);
    }

    #[test]
    fn test_empty_and_quotes() {
        assert_eq!(tokenize(""), Vec::<String>::new());
        assert_eq!(tokenize("''"), vec![""]);
        assert_eq!(tokenize("a''b"), vec!["ab"]);
    }
}
"
