    QUEUE.with(|q| q.borrow_mut().push_back(Box::new(f)));
    IS_RUNNING.with(|running| {
        if *running.borrow() {
            return;
        }
        *running.borrow_mut() = true;
        loop {
            let task = QUEUE.with(|q| q.borrow_mut().pop_front());
            if let Some(task) = task {
                task();
            } else {
