/// The `DragState` will act as a communication layer between the Provider's Event Listeners 
/// and any child element's internal Signals. We use `Signal<Option<Target>>` as it avoids 
/// triggering rebuilds on components that don't need it.
#[derive(Clone, Copy)]
pub struct DragState {
    // We store the target coordinates Signal, cursor offsets, and the target's is_dragged Signal.
    pub active_target: Signal<Option<(Signal<(f64, f64)>, f64, f64, Signal<bool>)>>,
}

/// Reusable Wrapper Component that tracks global drag movement and releases.
#[component]
pub fn DragProvider(children: Element) -> Element {
    // Initialize the DragState with no active target
    let mut drag_state = use_context_provider(|| DragState {
        active_target: Signal::new(None),
    });

    rsx! {
        div {
            style: "width: 100vw; height: 100vh; overflow: hidden; position: relative;",

            // When the mouse moves, update the precise node that initiated the drag
            onmousemove: move |e| {
                if let Some((mut target, offset_x, offset_y, _)) = *drag_state.active_target.read() {
                    let mouse = e.client_coordinates();
                    // Directly writing to the target Signal informs ONLY the target child to re-render!
                    target.set((mouse.x + offset_x, mouse.y + offset_y));
                }
            },
            // Release handles across the entire window area
            onmouseup: move |_| {
                if let Some((_, _, _, mut is_dragged)) = *drag_state.active_target.read() {
                    is_dragged.set(false);
                }
                drag_state.active_target.set(None);
            },
            onmouseleave: move |_| {
                if let Some((_, _, _, mut is_dragged)) = *drag_state.active_target.read() {
                    is_dragged.set(false);
                }
                drag_state.active_target.set(None);
            },

            // Render nested user components (SVG)
            {children}
        }
    }
}

