pub fn Point(props: PointProps) -> Element {
    // Each point independently maintains its local state 
    let mut coords = use_signal(|| (props.x, props.y));
    let mut is_dragged = use_signal(|| false);
    let mut drag_state = use_context::<DragState>();

    // Using `.read()` inside the rendering closure registers the point to automatically redraw itself
    // locally whenever these exact signals are changed by the DragProvider.
    let current_coords = *coords.read();
    let dragged_val = *is_dragged.read();

    rsx! {
        circle {
            cx: "{current_coords.0}",
            cy: "{current_coords.1}",
            r: "{props.r}",
