  "main.rs": "use std::sync::{Arc, Mutex};
use rustyline::{
    Cmd, DefaultEditor, Event::KeySeq, EventHandler::Conditional, KeyEvent, Modifiers,
};

fn main() {
    let mut rl = DefaultEditor::new().unwrap();

    // In rustyline, any text inserted directly into the buffer (e.g., via Cmd::Insert)
    // is fully editable by the user. There's no native way to make part of an active 
    // buffer read-only.
    // 
    // To achieve a true, read-only continuation prompt, the idiomatic technique is 
    // to exit the `readline` call (via AcceptLine) when Ctrl-J is pressed, and 
    // then read the next line with a different prompt string (e.g., ".. ").

    // 1. Create a shared flag to communicate when Ctrl-J triggers the line acceptance.
    let force_continuation = Arc::new(Mutex::new(false));
    let force_continuation_clone = Arc::clone(&force_continuation);

    // 2. Bind Ctrl-J to set the flag and accept the line
    rl.bind_sequence(
        KeySeq(vec![KeyEvent::new('j', Modifiers::CTRL)]),
        Conditional(Box::new(move |_, _| {
            if let Ok(mut flag) = force_continuation_clone.lock() {
                *flag = true;
            }
            Some(Cmd::AcceptLine)
        })),
    );

    let mut code_buffer = String::new();

    loop {
        // 3. Display main prompt or continuation prompt depending on the state
        let prompt = if code_buffer.is_empty() {
            ">> "
        } else {
            ".. "
        };

        match rl.readline(prompt) {
            Ok(line) => {
                code_buffer.push_str(&line);

                // 4. Check if we should continue (Ctrl-J was pressed)
                let is_continuation = {
                    // Read the scoped lock and reset it immediately
                    let mut flag = force_continuation.lock().unwrap();
                    let val = *flag;
                    *flag = false; 
                    val
                };

                if is_continuation {
                    // User wants to continue on a new line
                    code_buffer.push('\n');
                    continue; // Skip evaluating and prompt again
                }

                // 5. Normal submission via Enter key
                println!("\n--- Executing ---\n{}", code_buffer);
                // Do something with `code_buffer` here...

                // Add the full block to history so the user can recall it entirely
                let _ = rl.add_history_entry(code_buffer.as_str());

                // Reset state for the next command
                code_buffer.clear();
            }
            Err(_) => {
                // Handles ReadlineError::Interrupted (Ctrl-C) and Eof (Ctrl-D)
                break;
            }
        }
    }
