use std::ffi::CString;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread;
use std::time::{Duration, Instant};

use base64::{engine::general_purpose::STANDARD, Engine};
use termion::terminal_size_pixels;

struct ShmBuffer {
    name: String,
    size: usize,
    ptr: *mut u8,
    fd: libc::c_int,
}

impl ShmBuffer {
    fn new(name: &str, size: usize) -> Self {
        let c_name = CString::new(name).unwrap();
        unsafe {
            // Unlink first just in case a previous run crashed and left it
            libc::shm_unlink(c_name.as_ptr());

            let fd = libc::shm_open(c_name.as_ptr(), libc::O_CREAT | libc::O_RDWR, 0o600);
            if fd < 0 {
                panic!("shm_open failed: {:?}", io::Error::last_os_error());
            }

            let res = libc::ftruncate(fd, size as libc::off_t);
            if res != 0 {
                panic!("ftruncate failed: {:?}", io::Error::last_os_error());
            }

            let ptr = libc::mmap(
                std::ptr::null_mut(),
                size,
                libc::PROT_READ | libc::PROT_WRITE,
                libc::MAP_SHARED,
                fd,
                0,
            );
            if ptr == libc::MAP_FAILED {
                panic!("mmap failed: {:?}", io::Error::last_os_error());
            }

            Self {
                name: name.to_string(),
                size,
                ptr: ptr as *mut u8,
                fd,
            }
        }
    }

    fn slice_mut(&mut self) -> &mut [u8] {
        unsafe { std::slice::from_raw_parts_mut(self.ptr, self.size) }
    }
}

impl Drop for ShmBuffer {
    fn drop(&mut self) {
        let c_name = CString::new(self.name.as_str()).unwrap();
        unsafe {
            libc::munmap(self.ptr as *mut libc::c_void, self.size);
            libc::close(self.fd);
            libc::shm_unlink(c_name.as_ptr());
        }
    }
}

