    // We use two buffers so we can draw to one while the terminal reads the other.
    let pid = std::process::id();
    let mut shm_buffers = [
        ShmBuffer::new(&format!("/kitty_anim_{}_1", pid), size),
        ShmBuffer::new(&format!("/kitty_anim_{}_2", pid), size),
