//! and asynchronous handlers in a Rust web server routing API.
//!
//! ### The HRTB / Opaque Future Workaround
//! The compilation error you found (`one type is more general than the other`) 
//! is a known limitation in the Rust compiler (often referred to as issue #70263) 
//! regarding Higher-Ranked Trait Bounds (HRTB) and `async fn` that return opaque 
//! futures which borrow heavily from inputs (like `&Request`).
//!
//! To offer the simple API you want without writing complex macros, 
//! the idiomatic workaround used by almost all major Rust web frameworks 
//! (like `axum`, `actix-web`) is to pass the `Request` **by value** rather than 
//! by reference. 
//!
//! By passing `Request` by value (you can wrap it in an `Arc<Request>` or use 
//! cheap-to-clone Structs), the returned Future becomes `'static` and 
//! no longer captures references. This completely sidesteps the compiler bug.

use futures::future::BoxFuture;
use std::sync::Arc;
use std::collections::HashMap;

// 1. Define Request and Response
// Using `Clone` (or `Arc<Inner>`) makes Pass-by-Value cheap.
#[derive(Clone)]
pub struct Request;
pub struct Response;

// 2. Trait to unify Handlers
// We use a Marker system to selectively apply `impl Handler` to either sync
// or async functions without overlapping trait implementations.
pub trait Handler<Marker>: Send + Sync + 'static {
    fn call(&self, req: Request) -> BoxFuture<'static, Response>;
}

// Specific zero-sized Markers for compiler inference
pub struct SyncMarker;
pub struct AsyncMarker;

// 3. Implement for Sync functions
// Specifically matches Fn(Request) -> Response
impl<F> Handler<SyncMarker> for F
where
    F: Fn(Request) -> Response + Send + Sync + 'static,
{
    fn call(&self, req: Request) -> BoxFuture<'static, Response> {
        let res = self(req);
        Box::pin(std::future::ready(res))
    }
}

// 4. Implement for Async functions
// Specifically matches Fn(Request) -> Future<Output = Response>
impl<F, Fut> Handler<AsyncMarker> for F
where
    F: Fn(Request) -> Fut + Send + Sync + 'static,
    Fut: std::future::Future<Output = Response> + Send + 'static,
{
    fn call(&self, req: Request) -> BoxFuture<'static, Response> {
        Box::pin(self(req))
    }
}

// 5. Build the Server
// We use a type-erased closure to store the handlers uniformly.
type ErasedHandler = dyn Fn(Request) -> BoxFuture<'static, Response> + Send + Sync + 'static;

pub struct Server {
    routes: HashMap<String, Arc<ErasedHandler>>,
}

impl Server {
    pub fn new() -> Self {
        Self {
            routes: HashMap::new(),
        }
    }

    // `add_route` takes any type `H` that implements `Handler<M>`.
    // The Rust compiler will automatically infer to use either SyncMarker or AsyncMarker
    // based on the function signature passed by the user.
    pub fn add_route<M, H>(&mut self, path: &str, handler: H)
    where
        M: 'static,
        H: Handler<M>,
    {
        let erased: Arc<ErasedHandler> = Arc::new(move |req| handler.call(req));
        self.routes.insert(path.to_string(), erased);
    }
}

// ==========================================
// USER CODE EXAMPLE
// ==========================================

// Now users can write incredibly simple functions. 
// Request is passed by value (which could be an Arc under the hood to prevent expensive cloning).
fn sync_handler(_req: Request) -> Response {
    println!("Sync handler called!");
    Response
}

async fn async_handler(_req: Request) -> Response {
    println!("Async handler called!");
    Response
}

fn main() {
    let mut server = Server::new();

    // The exact same API works effortlessly for both sync and async functions!
    server.add_route("/sync", sync_handler);
    server.add_route("/async", async_handler);

