/// Instead of shifting subtrees when paths evaluate to nothing (e.g. `devices::{smart}` -> `{smart}`),
/// we convert the relative parent conceptually to `self::{smart}`, which allows us to safely and functionally
/// rewrite nodes in-place while keeping indentation, whitespace, and list structure perfectly intact.
fn process_use_tree(tree: ast::UseTree, mut ends_with_vexide: bool) {
    if let Some(path) = tree.path() {
        let mut new_segments = Vec::new();
        let mut path_changed = false;

        for segment in path.segments() {
            let seg_str = segment.syntax().text().to_string().trim().to_string();

            // If we found 'devices' right after a 'vexide', strip it out of the new path.
            if seg_str == "devices" && ends_with_vexide {
                path_changed = true;
                // Don't update ends_with_vexide, because conceptually the segment was skipped.
            } else {
                new_segments.push(seg_str.clone());
                ends_with_vexide = seg_str == "vexide";
            }
        }

        if path_changed {
            // If an interior list evaluates its parent path to nothing, 
            // substitute with `self` to preserve valid Rust syntax (e.g., `vexide::{self, fs}`).
            if new_segments.is_empty() {
                new_segments.push("self".to_string());
