  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};
use std::time::Duration;

pub enum TryPollResult<X> {
    Ready(X),
    Pending,
}

// A pure standard-library no-op waker. 
// (For Rust 1.85+, you can use `std::task::Waker::noop()` instead)
fn noop_waker() -> Waker {
    const VTABLE: RawWakerVTable = RawWakerVTable::new(
        |data| RawWaker::new(data, &VTABLE),
        |_| {}, // wake
        |_| {}, // wake_by_ref
        |_| {}, // drop
    );
    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

/// Polls a future synchronously without awaiting.
///
/// We require `F: Unpin` so we can safely poll via `&mut F`.
/// If your future is `!Unpin` (as `async fn` outputs normally are), 
/// you should pin it on the heap first (e.g. `Box::pin(fut)`).
/// A `Pin<Box<F>>` natively implements `Future` and is logically `Unpin`.
pub fn try_poll<F, X>(future: &mut F) -> TryPollResult<X>
where
    F: Future<Output = X> + Unpin,
{
    // 1. We construct a context with a no-op waker.
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    // 2. We poll the future securely (safe since F is Unpin)
    match Pin::new(future).poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// --- Example Usage ---

async fn delayed_task(immediate: bool) -> String {
    if immediate {
        "Immediate Result".to_string()
    } else {
        // Yields execution during the first poll
        tokio::time::sleep(Duration::from_millis(50)).await;
        "Delayed Result".to_string()
    }
}

/// A standard synchronous function executed in Tokio context
fn execute_and_handle(immediate: bool, run_id: u32) {
    // 1. Create the future and pin it on the heap.
    // Heap-pinning (Box::pin) is crucial here because we want to manually 
    // poll it now, AND still be able to move it into `tokio::spawn` later.
    let mut pinned_future = Box::pin(delayed_task(immediate));

    // 2. Poll the future synchronously securely via `&mut` reference.
    match try_poll(&mut pinned_future) {
        TryPollResult::Ready(val) => {
            // The future returned its output without yielding
            println!("[Run {}] Sync execution: Future completed immediately: {}", run_id, val);
        }
        TryPollResult::Pending => {
            // The future yielded.
            println!("[Run {}] Sync execution: Future is Pending. Spawning a new task...", run_id);

            // 3. We successfully retained ownership of `pinned_future` and can 
            // securely send it to a dynamically spawned task without blocking.
            tokio::spawn(async move {
                // The internal Tokio executor will apply a real Waker context over 
                // the prior `noop_waker` seamlessly upon the first `await` poll here.
                let val = pinned_future.await;
                println!("[Run {}] Async task: Future completed asynchronously: {}", run_id, val);
            });
        }
    }
}

#[tokio::main]
async fn main() {
    println!("--- Testing a future that is ready instantly ---");
    execute_and_handle(true, 1);

    println!("\n--- Testing a future that requires awaiting ---");
    execute_and_handle(false, 2);

    // Block briefly in main to give the background task enough time to complete out-of-band
    tokio::time::sleep(Duration::from_millis(150)).await;
}
"
}
