pub struct Context(pub i32);

pub enum InnerAsyncEvent {
    DoWithContext {
        // Using FnOnce here matches typical "send workload over channel once" semantics.
        // If you need it to be reusable, change it to Fn and take `&self` below.
        block: Box<
