// 1. We create a custom helper trait. 
//    The missing piece in standard stable Rust is bounding the generated future as `Send`.
//    This trait forces the returned Future to implement `Send`.
pub trait AsyncFnOnceContext<'a> {
    type Fut: Future<Output = ()> + Send + 'a;
    fn call_once(self, ctx: &'a mut Context) -> Self::Fut;
}

// 2. We implement this helper for any FnOnce that returns an appropriate Future.
//    Named async functions seamlessly match this shape on stable Rust.
//    (Also, in Rust 1.85+, `async |ctx| {}` closures will naturally match this).
impl<'a, F, Fut> AsyncFnOnceContext<'a> for F
where
    F: FnOnce(&'a mut Context) -> Fut,
    Fut: Future<Output = ()> + Send + 'a,
{
    type Fut = Fut;
    fn call_once(self, ctx: &'a mut Context) -> Self::Fut {
        self(ctx)
    }
}

