  "main.rs": "use signal_hook::consts::signal::{SIGINT, SIGTERM};
use signal_hook::iterator::Signals;
use std::io::{self, Write};
use std::sync::mpsc::{self, Sender};
use std::thread;
use termion::event::{Event, Key};
use termion::input::TermRead;
use termion::raw::IntoRawMode;

enum Message {
    Key(Key),
    Signal(i32),
}

fn yield_signals(sender: Sender<Message>, mut signals: Signals) {
    for sig in signals.forever() {
        // If the main thread drops the receiver, `send` returns an Error and we break out of the loop
        if sender.send(Message::Signal(sig)).is_err() {
            break;
        }
    }
}

fn yield_keys(sender: Sender<Message>) {
    let stdin = io::stdin();
    for event in stdin.events() {
        if let Ok(Event::Key(key)) = event {
            // Same here, stop if receiver is dropped
            if sender.send(Message::Key(key)).is_err() {
                break;
            }
        }
    }
}

fn main() {
    let (sender, receiver) = mpsc::channel();

    // 1. SETUP SIGNALS
    // By defining `Signals` in main, we can grab a "handle" to close it later
    // before moving the `signals` iterator into the background thread.
    let signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();
    let signals_handle = signals.handle();

    let sender_signals = sender.clone();
    let thread_signals = thread::spawn(move || {
        yield_signals(sender_signals, signals);
    });

    // 2. SETUP TERMINAL RAW MODE IN `MAIN`
    // The original code had `into_raw_mode()` inside `yield_keys`.
    // By keeping `stdout` in `main()`, we guarantee the terminal's raw mode 
    // is properly restored via RAII when `main` finishes and returns!
    let mut stdout = io::stdout().into_raw_mode().unwrap();

    // 3. SETUP KEYBOARD INPUT
    let sender_keys = sender.clone();
    thread::spawn(move || {
        yield_keys(sender_keys);
    });

    write!(
        stdout,
        "{}{}\r\nPress 'q' or send SIGTERM to exit.\r\n",
        termion::clear::All,
        termion::cursor::Goto(1, 1)
    )
    .unwrap();
    stdout.flush().unwrap();

    // 4. MAIN EVENT LOOP
    for msg in receiver.iter() {
        match msg {
            Message::Key(Key::Char('q')) | Message::Key(Key::Ctrl('c')) => {
                write!(stdout, "\r\nUser requested exit. Exiting...\r\n").unwrap();
                break;
            }
            Message::Key(key) => {
                write!(stdout, "Key pressed: {:?}\r\n", key).unwrap();
            }
            Message::Signal(sig) => {
                write!(stdout, "\r\nReceived signal: {}. Exiting...\r\n", sig).unwrap();
                break;
            }
        }
        stdout.flush().unwrap();
    }

    // 5. CLEANUP BACKGROUND THREADS
    // We can stop the `signal_hook` infinite loop gracefully via the handle.
    signals_handle.close();
    let _ = thread_signals.join();

    // For `yield_keys`, `io::stdin()` is inherently blocking in rust on all operating systems. 
    // To cleanly stop it without using complex async frameworks, we rely on the process teardown.
    // Because we moved the `RawTerminal` to `main`, we don't need to manually terminate `stdin`.
    // When `main` returns here, the `stdout` variable drops, returning the terminal to its normal 
    // state, and the OS terminates the safely parked stdin thread without corruption.
}
"
}
