        if constructed {
            let fixed_content = fix_der(content);
            out.push(tag);
            out.extend(encode_len(fixed_content.len()));
            out.extend(fixed_content);
        } else if tag == 0x02 {
            // INTEGER specific: Strip redundant zeroes to strictly abide by DER rules
            let mut val = content;
            while val.len() > 1 && val[0] == 0x00 && (val[1] & 0x80) == 0 {
                val = &val[1..];
            }
            // Also strip redundant `0xFF` bytes for negative integers just in case
            while val.len() > 1 && val[0] == 0xFF && (val[1] & 0x80) != 0 {
                val = &val[1..];
            }
            if val.is_empty() {
                val = &[0];
            }
            out.push(tag);
            out.extend(encode_len(val.len()));
            out.extend(val);
        } else {
            out.push(tag);
            out.extend(encode_len(content.len()));
            out.extend(content);
        }
    }
    out
}

fn encode_len(len: usize) -> Vec<u8> {
    if len < 0x80 {
        vec![len as u8]
    } else {
        let mut len_bytes = Vec::new();
        let mut l = len;
        while l > 0 {
            len_bytes.push((l & 0xFF) as u8);
            l >>= 8;
        }
        len_bytes.reverse();
        let mut out = vec![0x80 | len_bytes.len() as u8];
        out.extend(len_bytes);
        out
    }
}

fn main() {
