    ray_dir: Vec3,
    obb_center: Vec3,
    obb_size: Vec3,
    obb_rotation: Quat,
) -> Option<(Vec3, Vec3)> {
    let local_ray_dir = obb_rotation.inverse() * ray_dir;
    let local_ray_origin = obb_rotation.inverse() * (ray_origin - obb_center);

    let mut tmin = f32::NEG_INFINITY;
    let mut tmax = f32::INFINITY;
    let mut normal = Vec3::ZERO;

    for i in 0..3 {
        if local_ray_dir[i].abs() < 1e-6 {
            if local_ray_origin[i] < -obb_size[i] / 2.0 || local_ray_origin[i] > obb_size[i] / 2.0 {
                return None;
            }
