            let inv_d = 1.0 / local_ray_dir[i];
            let mut t0 = (-obb_size[i] / 2.0 - local_ray_origin[i]) * inv_d;
            let mut t1 = (obb_size[i] / 2.0 - local_ray_origin[i]) * inv_d;
            let mut n0 = Vec3::ZERO;
            n0[i] = -1.0;
            let mut n1 = Vec3::ZERO;
            n1[i] = 1.0;

            if t0 > t1 {
                std::mem::swap(&mut t0, &mut t1);
                std::mem::swap(&mut n0, &mut n1);
            }

            if t0 > tmin {
                tmin = t0;
                normal = n0;
            }
            if t1 < tmax {
                tmax = t1;
            }
            if tmin > tmax {
                return None;
            }
        }
    }

    if tmax < 0.0 {
        return None;
    }

    let t = if tmin < 0.0 { tmax } else { tmin };
    let hit_pos = ray_origin + ray_dir * t;
    let world_normal = obb_rotation * normal;

    Some((hit_pos, world_normal))
}
