    // Unlike languages/libraries with implicit broadcasting (like NumPy),
    // nalgebra expects explicit operations. The most idiomatic and efficient
    // way to center columns is to iterate over them and mutate them in place,
    // completely avoiding the allocation of an n x k mean matrix.
    let mut centered = matrix.clone();
    for mut col in centered.column_iter_mut() {
        let mean = col.mean();
        for val in col.iter_mut() {
            *val -= mean;
        }
