use std::os::unix::io::{AsRawFd, FromRawFd};
use std::sync::{Arc, Mutex};
use std::thread;

/// A pattern for interactive PTY pass-through without blocking out writes.
pub struct Agent {
    /// The writer possesses an exclusively duplicated file handle tied to the PTY.
    /// It lives separately from the read session, naturally resolving thread locks.
    writer: Arc<Mutex<std::fs::File>>,
}

impl Agent {
    /// Spawns the agent, executing the underlying split of the PTY session.
    pub fn new() -> Result<Self, String> {
        // Spawn the expectrl session.
        // Using "sh" for standard Apple Silicon local testing.
        let mut session = expectrl::spawn("sh").map_err(|e| e.to_string())?;

        // 1. Extract the Raw File Descriptor from the Session's PTY master.
        // On Unix, expectrl's Session seamlessly implements AsRawFd.
        let fd = session.as_raw_fd();

        // 2. Safely clone the file descriptor into an independent writer Handle.
        let clone_err = "Failed to clone PTY file descriptor";
        let writer_file = {
            // Wrap raw fd in ManuallyDrop so we do not close the underlying master.
            let temporary_ptr = std::mem::ManuallyDrop::new(unsafe { std::fs::File::from_raw_fd(fd) });
            // try_clone() runs a safe fcntl(F_DUPFD_CLOEXEC) without extra libc bindings!
            temporary_ptr.try_clone().map_err(|_| clone_err.to_string())?
        };

        let writer = Arc::new(Mutex::new(writer_file));
        let writer_handle = writer.clone();

