use std::sync::Arc;
use tracing::{info, span, Instrument, Level, Span};

/// Simulate Pingora's proxy trait.
/// In actual Pingora, you implement similar methods that provide a mutable context.
#[async_trait]
pub trait ProxyHttp {
    type CTX: Send + Sync;
    fn new_ctx(&self) -> Self::CTX;
    async fn request_filter(&self, ctx: &mut Self::CTX);
    async fn upstream_filter(&self, ctx: &mut Self::CTX);
}

pub struct MyProxy;

/// Our custom context object that Pingora allows us to define.
pub struct MyContext {
    // We store the parent tracing span here so we can access it on any thread.
    // Both tracing and tracing-opentelemetry interact flawlessly with this struct.
    pub parent_span: Span,
}

#[async_trait]
impl ProxyHttp for MyProxy {
    type CTX = MyContext;

    fn new_ctx(&self) -> Self::CTX {
        // 1. Initialize the parent span when the context is created (start of lifecycle).
        let parent_span = span!(Level::INFO, "Request/Parent Span");
        MyContext { parent_span }
    }

    async fn request_filter(&self, ctx: &mut Self::CTX) {
        // 2. REHYDRATION METHOD A: Using `.instrument()`
        // By wrapping our async logic in an `async {}` block and instrumenting it
        // with a clone of the parent span, we make the parent span ACTIVE for this task.
        // Cloning a `tracing::Span` is cheap (just an atomic ref-count bump).
        async {
            let stage_span = span!(Level::INFO, "Stage 1 Span");
            async {
                info!("Running stage 1 - request_filter");
                tokio::time::sleep(std::time::Duration::from_millis(10)).await;
            }
            .instrument(stage_span)
            .await;
        }
        .instrument(ctx.parent_span.clone())
        .await;
    }

    async fn upstream_filter(&self, ctx: &mut Self::CTX) {
        // 2. REHYDRATION METHOD B: Explicit Parent linking
        // You can also explicitly set the parent of the child span. This achieves the 
        // same hierarchical Tracing/OTel graph without needing to `.instrument()` the parent first.
        let stage_span = span!(parent: &ctx.parent_span, Level::INFO, "Stage 2 Span");

        async {
            info!("Running stage 2 - upstream_filter");
            tokio::time::sleep(std::time::Duration::from_millis(10)).await;

            // Child of Stage 2 (implicitly connected down to Parent Span)
            let upstream_span = span!(Level::INFO, "Upstream");
            async {
                info!("Connecting to upstream server");
                tokio::time::sleep(std::time::Duration::from_millis(10)).await;
            }
            .instrument(upstream_span)
            .await;
        }
        .instrument(stage_span)
        .await;
    }
}

/// Simulate Tokio executing Pingora stages across disjoint tasks/threads.
/// This demonstrates that even if Tokio moves execution contexts, our trace properly nests.
async fn simulate_pingora_request<P: ProxyHttp + Send + Sync + 'static>(proxy: P) {
    let mut ctx = proxy.new_ctx();
    let proxy_arc = Arc::new(proxy);

    let p = proxy_arc.clone();
    tokio::spawn(async move {
        p.request_filter(&mut ctx).await;

        // Simulate Pingora dispatching the next step to a totally different background task
        let p2 = p.clone();
        tokio::spawn(async move {
            p2.upstream_filter(&mut ctx).await;
        })
        .await
        .unwrap();
    })
    .await
    .unwrap();
}

#[tokio::main]
async fn main() {
    // Initialize the tracing subscriber.
    // Standard log output will natively show active span context in braces.
    // When you integrate OpenTelemetry (`tracing-opentelemetry`), this identical span
    // structure will be automatically exported as an accurate waterfall to your OTLP collector.
    tracing_subscriber::fmt()
        .with_max_level(tracing::Level::INFO)
        .init();

    info!("Starting simulated Pingora request lifecycle");
    simulate_pingora_request(MyProxy).await;
    info!("Request completed");
}
