    let stdout = io::stdout();
    let mut handle = stdout.lock();

    // Hide cursor to prevent flickering at the cursor location
    write!(handle, "\x1b[?25l").unwrap();
    let _cleanup = CursorCleanup;

    let mut time: f32 = 0.0;
    let mut frame: usize = 0;

