        let frame_start = Instant::now();

        let (mut width, mut height) = terminal_size_pixels().unwrap_or((640, 480));
        // Fall back gracefully if unsupported by TTY
        if width == 0 || height == 0 {
            width = 640;
            height = 480;
        }
        let (width, height) = (width as usize, height as usize);
        let size = width * height * 3;

        let shm_name_str = format!("/kitty-anim-{}-{}", std::process::id(), frame);
        let c_name = CString::new(shm_name_str.as_str()).unwrap();

        let mut guard = ShmGuard {
            name: c_name.clone(),
            opened: false,
            defused: false,
        };

        // Create and write directly to an anonymous shared memory buffer via mem mapping
        unsafe {
            let fd = libc::shm_open(
                guard.name.as_ptr(),
                libc::O_CREAT | libc::O_RDWR | libc::O_EXCL,
                0o600,
            );

            if fd < 0 {
