//! Declarative Macro (`macro_rules!`) which wraps around your trait. Since declarative macros 
//! act locally wherever they are invoked across crate boundaries, you achieve the exact 
//! static dispatch performance as `enum_dispatch` but securely across completely separate crates!

// ------------------------------------------------------------------------
// LAYER 1: Abstract Layer (al)
// ------------------------------------------------------------------------
pub mod al {
    use ambassador::delegatable_trait;

    /// The abstract layer defines the traits.
    /// `#[delegatable_trait]` automatically parses the 20+ methods and generates
    /// a declarative macro in the background.
    #[delegatable_trait]
    pub trait Rest {
        fn get(&self) -> String;
        fn post(&mut self, payload: &str) -> bool;
        // ... imagine your 18 other methods here
    }
}

// ------------------------------------------------------------------------
// LAYER 2: Implementation Layer (il)
// ------------------------------------------------------------------------
pub mod il {
    // In a workspace, this would be: `use al::Rest;`
    use super::al::Rest;

    pub struct Foo {
        pub state: String,
    }

    impl Rest for Foo {
        fn get(&self) -> String {
            format!("Foo state: {}", self.state)
        }

        fn post(&mut self, payload: &str) -> bool {
            self.state = payload.to_string();
            true
        }
    }

    pub struct Boo {
        pub code: i32,
    }

    impl Rest for Boo {
        fn get(&self) -> String {
            format!("Boo code: {}", self.code)
        }

        fn post(&mut self, payload: &str) -> bool {
            if let Ok(c) = payload.parse() {
                self.code = c;
                true
            } else {
                false
            }
        }
    }
}

// ------------------------------------------------------------------------
// LAYER 3: Business Layer (bl)
// ------------------------------------------------------------------------
pub mod bl {
    use ambassador::Delegate;

    // In a complete workspace setup, you would import them as:
    // use al::Rest; 
    // use il::{Foo, Boo};
    use super::al::Rest;
    use super::il::{Boo, Foo};

    /// By deriving `Delegate` and pointing the `delegate` attribute to `Rest`,
    /// `ambassador` will expand the underlying macro from the `al` crate,
    /// automatically matching every variant and safely statically dispatching 
    /// all 20+ methods of the trait.
    #[derive(Delegate)]
    #[delegate(Rest)]
    pub enum Item {
        Foo(Foo),
        Boo(Boo),
    }
}

// ------------------------------------------------------------------------
// Execution Logic
// ------------------------------------------------------------------------
