/// Tries to poll a future synchronously without consuming it.
/// 
/// The future needs to be `Unpin`, which is typical when you `Box::pin` 
/// an async block before attempting to evaluate it.
///
/// # Why this works:
/// `&mut F` implements `Future` when `F: Unpin`.
/// Calling `.now_or_never()` therefore consumes the *mutable reference* 
/// rather than the underlying future itself, maintaining your ownership
/// of the future so you can still spawn it if it returns `Pending`.
pub fn try_poll<F>(future: &mut F) -> TryPollResult<F::Output>
where
    F: Future + Unpin,
{
    // `now_or_never` creates a dummy `noop_waker` and polls the future with it.
    match future.now_or_never() {
        Some(val) => TryPollResult::Ready(val),
        None => TryPollResult::Pending,
    }
}

/// A regular, non-async function that is executed within an async Tokio context.
fn evaluate_future_sync_or_spawn<F>(mut fut: F)
where
    F: Future<Output = String> + Unpin + Send + 'static,
{
