  "main.rs": "//! Solution Explanation: Why were metrics dropping silently?
//!
//! 1. **OS Socket Drop (Lossy Datagrams):** Datagram sockets (both UDP and Unix DataGram/UDS)
//!    are lossy. When you send high throughput metrics without batching them together, you overwhelm 
//!    the Datadog agent's receive queue (`max_dgram_qlen`). The Linux kernel will silently drop 
//!    the excess packets without any errors on your `.send()` calls.
//!
//! 2. **Lack of client-side batching:** The default `cadence` Unix behavior does not batch.
//!    To fix this, we implement a proper `BufferedUnixMetricSink` that batches strings using `\n` 
//!    into a large 8KB payload, sending thousands of metrics in a single OS syscall.
//!
//! 3. **Queuing Constraints:** `QueuingMetricSink` processes metrics asynchronously, but its 
//!    default capacity is very small. In a high-throughput `poem` server, you'll easily overwhelm 
//!    it. We fixed this by initiating it via `.with_capacity(unix_sink, 524288)`.

use cadence::{MetricSink, NopMetricSink, QueuingMetricSink, StatsdClient, CountedExt};
use std::os::unix::net::UnixDatagram;
use std::sync::{Arc, Mutex};
use std::time::Duration;
use std::thread;

// Pointing to /tmp/dsd.socket for local `cargo run` demonstration.
// Change back to "/var/run/datadog/dsd.socket" for ECS Fargate.
const SOCKET_PATH: &str = "/tmp/dsd.socket";
const METRIC_PREFIX: &str = "my_service";
const MAX_RETRIES: usize = 5;

/// A thread-safe, auto-flushing, batch-buffering MetricSink. 
/// Groups Datadog statsd metrics together natively to heavily lower 
/// OS packet drops on high QPS endpoints.
pub struct BufferedUnixMetricSink {
    buf: Arc<Mutex<String>>,
    sock: Arc<UnixDatagram>,
    capacity: usize,
}

impl BufferedUnixMetricSink {
    pub fn from(_path: &str, sock: UnixDatagram) -> Self {
        // 1. Attempt to maximize kernel sender buffer 
        let _ = sock.set_send_buffer_size(8 * 1024 * 1024);

        let buf = Arc::new(Mutex::new(String::with_capacity(8192)));
        let arc_sock = Arc::new(sock);

        let buf_clone = Arc::clone(&buf);
        let sock_clone = Arc::clone(&arc_sock);

        // 2. Background thread to flush stagnant metrics periodically (e.g. at night when throughput drops)
        thread::spawn(move || {
            loop {
                thread::sleep(Duration::from_millis(500));
                let mut guard = buf_clone.lock().unwrap();
                if !guard.is_empty() {
                    let _ = sock_clone.send(guard.as_bytes());
                    guard.clear();
                }
            }
        });

        Self {
            buf,
            sock: arc_sock,
            capacity: 8192 - 256, // Wait until ~8KB max payload limit
        }
    }
}

impl MetricSink for BufferedUnixMetricSink {
    fn emit(&self, metric: &str) -> std::io::Result<usize> {
        let mut guard = self.buf.lock().unwrap();

        // If adding this metric pushes us over payload limits, force flush.
        if guard.len() + metric.len() + 1 > self.capacity {
            if !guard.is_empty() {
                let _ = self.sock.send(guard.as_bytes());
                guard.clear();
            }
        }

        if !guard.is_empty() {
            guard.push('\n');
        }
        guard.push_str(metric);

        Ok(metric.len())
    }

    fn flush(&self) -> std::io::Result<()> {
        let mut guard = self.buf.lock().unwrap();
        if !guard.is_empty() {
            let _ = self.sock.send(guard.as_bytes());
            guard.clear();
        }
