    // Since both `String` and `MyData` are Send + Sync, `ParsedPayload` is safely Send + Sync. 
    // Arc effectively grants the required `'static` lifetime constraint enforced by `tokio::spawn`.
    let shared_payload = Arc::new(payload);

    let mut tasks = Vec::new();

