    if local_segments != new_local && !new_local.is_empty() {
        if let Some(old_path) = tree.path() {
            let new_path_str = new_local.join("::");
            let new_path_node = parse_path(&new_path_str);
            // Replaces the old path syntax tree node with the new one we constructed.
            ted::replace(old_path.syntax().clone(), new_path_node.syntax().clone());
        }
    }

    // Recurse into sub-trees.
    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            rewrite_use_tree(&child, full_orig.clone());
        }
    }
}

/// Parses a file, completely edits imports in place, and returns the modified source text.
pub fn rewrite_imports_in_file(text: &str) -> String {
    let parse = SourceFile::parse(text);
    let root = parse.tree().syntax().clone_for_update();

    let use_items: Vec<_> = root.descendants().filter_map(ast::Use::cast).collect();
    for use_item in use_items {
        if let Some(tree) = use_item.use_tree() {
            rewrite_use_tree(&tree, vec![]);
        }
    }

    root.to_string()
}

fn main() {
