fn ray_intersect_aabb(local_origin: Vec3, local_dir: Vec3, min: Vec3, max: Vec3) -> Option<(f32, Vec3)> {
    let mut t_near = f32::NEG_INFINITY;
    let mut t_far = f32::INFINITY;
    let mut normal_near = Vec3::ZERO;
    let mut normal_far = Vec3::ZERO;

    let origin_arr = local_origin.to_array();
    let dir_arr = local_dir.to_array();
    let min_arr = min.to_array();
    let max_arr = max.to_array();

    for i in 0..3 {
        let mut t1 = (min_arr[i] - origin_arr[i]) / dir_arr[i];
        let mut t2 = (max_arr[i] - origin_arr[i]) / dir_arr[i];
        let mut n1 = Vec3::ZERO; n1[i] = -1.0;
        let mut n2 = Vec3::ZERO; n2[i] = 1.0;

        if t1.is_nan() || t2.is_nan() { return None; }

        if t1 > t2 {
            std::mem::swap(&mut t1, &mut t2);
            std::mem::swap(&mut n1, &mut n2);
        }

        if t1 > t_near {
            t_near = t1;
            normal_near = n1;
        }
        if t2 < t_far {
            t_far = t2;
            normal_far = n2;
        }

        if t_near > t_far || t_far < 0.0 {
            return None;
        }
    }

    if t_near > 0.0 {
        Some((t_near, normal_near))
    } else {
        Some((t_far, normal_far))
    }
