use cms::signed_data::SignedData;
use der::Decode;

/// Recursive function to fix non-canonical DER integers.
/// 
/// The Rust `der` crate is strictly conforming and panics/errors on integers 
/// that contain redundant leading zeros. Many SCEP implementations (e.g. Cisco, NDES)
/// incorrectly encode values like `serialNumber` or `transactionID` as fixed 32-byte integers 
/// and prepend `0x00` even when the Highest-Order Bit isn't 1. 
/// This causes the exact error: `Value { tag: Tag(0x02: INTEGER) }`.
fn fix_der_tlvs(der: &[u8]) -> Vec<u8> {
    let mut out = Vec::new();
    let mut i = 0;
    while i < der.len() {
        let tag = der[i];
        if i + 1 >= der.len() {
            out.push(tag);
            break;
        }

        let mut len_bytes = 1;
        let mut len = der[i+1] as usize;
        if len >= 0x80 {
            let num_bytes = len & 0x7F;
            len_bytes += num_bytes;
            len = 0;
            for j in 0..num_bytes {
                if i + 2 + j >= der.len() { break; }
                len = (len << 8) | (der[i + 2 + j] as usize);
            }
        }

        let header_len = 1 + len_bytes;
        if i + header_len + len > der.len() {
            // Malformed length: preserve remaining bytes and break cautiously
            out.extend_from_slice(&der[i..]);
            break;
        }

        let value = &der[i + header_len .. i + header_len + len];
        let mut new_value = Vec::new();
        let is_constructed = (tag & 0x20) != 0;

        if is_constructed {
            // Recurse heavily nested SETs and SEQUENCEs
            new_value = fix_der_tlvs(value);
        } else if tag == 0x02 { // INTEGER
            let mut v = value;
            // Strip redundant leading zero bytes for positive integers
            while v.len() > 1 && v[0] == 0x00 && v[1] < 0x80 {
                v = &v[1..];
            }
            // Strip redundant leading 0xFF bytes for negative integers
            while v.len() > 1 && v[0] == 0xFF && v[1] >= 0x80 {
                v = &v[1..];
            }
            new_value = v.to_vec();
        } else {
            new_value = value.to_vec();
        }

        out.push(tag);
        // Recompute standard DER length bytes correctly
        let nl = new_value.len();
        if nl < 0x80 {
            out.push(nl as u8);
        } else {
            let mut l = nl;
            let mut lb = Vec::new();
            while l > 0 {
                lb.push((l & 0xFF) as u8);
                l >>= 8;
            }
            lb.reverse();
            out.push((0x80 | lb.len()) as u8);
            out.extend_from_slice(&lb);
        }
        out.extend_from_slice(&new_value);

        i += header_len + len;
    }
    out
}

pub fn process_scep_payload(body: &[u8]) {
